-- metadata 包含：cause、court_level、year、summary
-- status=0 表示无需向量化，按元数据检索
-- ============================================================

-- 先清除旧案例数据
DELETE FROM knowledge_doc WHERE doc_type = 'CASE';

-- 批量插入
INSERT INTO knowledge_doc (owner_type, owner_id, doc_type, title, source, metadata, raw_text, status, created_at) VALUES

('PUBLIC', NULL, 'CASE', '某建材公司诉某建筑公司买卖合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2015", "summary": "原告供应水泥，被告以质量不合格为由拒付尾款。法院认定被告未在异议期内提出异议，判决支付尾款及逾期利息。"}', '原告某建材公司与被告某建筑公司于2014年9月签订《水泥买卖合同》，约定原告向被告供应水泥共计500吨，总价款22万元。合同约定被告收货后15日内付款，如有质量问题应在收货后7日内书面提出。原告于2014年10月分批交付全部货物，被告收货时签署送货单但未注明质量异议。付款期限届满后，被告以部分水泥凝结时间不符合标准为由拒付尾款8万元。法院经审理查明，被告在收货时签署的送货单上未标注任何质量异议，且在合同约定的7日异议期内未书面提出质量问题。被告提交的检测报告系其在收货20日后单方委托作出，样品来源无法核实。法院认为，买受人收到标的物后应当在约定期间内进行检验，未在约定期间内提出异议的，视为标的物质量符合约定。判决被告支付原告尾款8万元及逾期利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某工程公司诉某开发商建设工程施工合同纠纷案', '某省高级人民法院', '{"cause": "合同纠纷", "court_level": "高级人民法院", "year": "2016", "summary": "原告承建被告商业综合体项目，竣工后被告以工期延误为由扣留工程款。法院认定工期延误部分系被告设计变更所致，判决支付工程款及利息。"}', '原告某工程公司与被告某开发商于2013年5月签订《建设工程施工合同》，约定原告承建被告开发的某商业综合体项目，合同总价款6800万元，工期540天。施工期间，被告多次进行设计变更，增加地下车库层数及外立面修改，导致工期顺延120天。工程于2015年6月竣工验收合格并交付使用。被告支付工程款5200万元后，以工期延误为由扣留1600万元。法院经审理查明，被告在施工期间先后发出12份设计变更通知单，经鉴定由此导致工期顺延约100天。实际延误天数扣除设计变更影响后，原告仅延误20天。工程已通过竣工验收合格，被告已实际使用。法院认为，因发包人变更计划等原因导致工期延误的，工期相应顺延。判决被告支付原告工程款1600万元及相应利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '张某诉李某房屋租赁合同纠纷案', '某区基层人民法院', '{"cause": "合同纠纷", "court_level": "基层人民法院", "year": "2017", "summary": "原告张某承租被告李某商铺经营餐饮，被告在租期内擅自断水断电致原告无法经营。法院判决解除合同、退还租金并赔偿损失。"}', '原告张某与被告李某于2016年3月签订《商铺租赁合同》，约定原告承租被告位于某商业街的商铺一间，租期三年，年租金12万元，按季支付。原告租赁后用于经营餐饮店，投入装修费用15万元。2017年1月，被告因租金上涨要求增加租金，原告拒绝后，被告于2017年2月擅自切断商铺水电，导致原告无法正常经营。原告多次协商未果，诉至法院请求解除合同、退还剩余租金并赔偿装修及经营损失。法院经审理查明，被告在租赁期内擅自断水断电，严重影响原告正常使用租赁物，构成根本违约。法院认为，出租人应当按照约定将租赁物交付承租人，并在租赁期内保持租赁物符合约定用途。判决解除租赁合同，被告退还原告未使用期间租金3万元，赔偿装修损失10万元及经营损失5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '王某诉赵某民间借贷合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2015", "summary": "原告王某借给被告赵某50万元，被告逾期未还。法院判决被告偿还本金及按年利率24%计算的利息。"}', '原告王某与被告赵某系朋友关系。2017年5月，被告以资金周转为由向原告借款50万元，双方签订《借款合同》，约定借款期限6个月，年利率24%，按月付息，到期还本。原告通过银行转账交付50万元。被告按月支付利息至2017年10月后停止付息，借款到期后也未偿还本金。原告多次催要未果，诉至法院。法院经审理查明，双方签订的借款合同系真实意思表示，原告已实际交付借款50万元，被告对借款事实无异议。关于利率，双方约定的年利率24%未超过法律规定的上限。法院认为，合法的借贷关系受法律保护，借款人应当按照约定的期限返还借款及支付利息。判决被告赵某偿还原告王某借款本金50万元，并按年利率24%支付自2017年11月起至实际清偿之日止的利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某装饰公司诉某酒店承揽合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2015", "summary": "原告承揽被告酒店装修工程，完工后被告以部分项目不合格为由拒付尾款。法院判决被告支付尾款及违约金。"}', '原告某装饰公司与被告某酒店于2018年8月签订《酒店装修承揽合同》，约定原告承揽被告酒店室内装修工程，合同总价款350万元，工期90天。合同约定分期付款，竣工验收合格后支付尾款105万元。原告按期完工并申请验收，被告以大堂吊顶造型与设计图纸不符为由拒绝验收并拒付尾款。法院经审理查明，大堂吊顶在施工过程中经被告口头同意进行了方案调整，被告已实际使用酒店营业达三个月。法院认为，承揽人完成工作的，应当向定作人交付工作成果，定作人应当验收。定作人已实际使用装修成果的，视为验收合格。被告主张的质量问题系其自行变更设计所致。判决被告支付原告尾款105万元及违约金。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某科技公司诉某研究所技术服务合同纠纷案', '某省高级人民法院', '{"cause": "合同纠纷", "court_level": "高级人民法院", "year": "2015", "summary": "原告为被告提供技术开发服务，被告以未达预期目标为由拒付服务费。法院判决被告支付服务费及违约金。"}', '原告某科技公司与被告某研究所于2019年6月签订《技术服务合同》，约定原告为被告开发某数据分析平台，合同总价款200万元，分三期支付。原告按约定成平台开发并交付，被告支付前两期款项共计140万元后，以平台运行性能未达到合同约定的技术指标为由拒付第三期尾款60万元。法院经审理查明，合同约定的技术指标包括数据处理速度和并发用户数两项。原告交付的平台经第三方检测，数据处理速度达到约定指标的95%，并发用户数完全达标。法院认为，技术服务合同的受托人已完成主要合同义务，技术指标轻微偏差不影响合同目的实现。被告未在合理期限内提出书面异议并已将平台投入实际使用。判决被告支付原告服务费60万元及逾期付款违约金。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某物流公司诉某制造公司运输合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2016", "summary": "原告承运被告货物，运输途中因交通事故致货物损毁。法院认定被告已投保货运险，判决保险理赔后原告赔偿不足部分。"}', '原告某物流公司与被告某制造公司于2016年3月签订《货物运输合同》，约定原告将被告生产的机械设备从某市运至另一市，运费5万元。运输途中，因原告驾驶员操作不当发生交通事故，导致部分设备损坏，损失约30万元。被告已就该批货物投保运输险，保险公司理赔20万元后，被告要求原告赔偿剩余10万元损失。原告主张其已尽到运输义务，事故系不可抗力。法院经审理查明，交通事故系驾驶员超速行驶所致，不属于不可抗力。原告作为承运人应对运输途中货物的毁损承担赔偿责任。法院认为，承运人对运输过程中货物的毁损、灭失承担损害赔偿责任，但不可抗力造成的除外。判决原告赔偿被告货物损失10万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '陈某诉某仓储公司保管合同纠纷案', '某区基层人民法院', '{"cause": "合同纠纷", "court_level": "基层人民法院", "year": "2015", "summary": "原告陈某将货物存放于被告仓库，货物因仓库漏水受损。法院判决被告赔偿货物损失。"}', '原告陈某与被告某仓储公司于2020年10月签订《仓储保管合同》，约定被告为原告存放服装一批，保管期6个月，保管费1.2万元。2021年1月，因仓库屋顶漏水，原告存放的部分服装受潮发霉，损失约8万元。原告要求被告赔偿，被告以漏水系暴雨所致不可抗力为由拒绝。法院经审理查明，仓库屋顶在存放前已存在裂缝，被告未及时维修，暴雨仅是加剧了漏水程度。法院认为，保管人对入库仓储物负有妥善保管的义务，因保管不善造成仓储物毁损灭失的，保管人应当承担损害赔偿责任。仓库屋顶裂缝系被告维护不当所致，不属于不可抗力。判决被告赔偿原告货物损失8万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某电力公司诉某制造公司供用电合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2018", "summary": "被告拖欠电费，原告起诉要求支付电费及违约金。法院判决被告支付电费及违约金。"}', '原告某电力公司与被告某制造公司于2016年签订《供用电合同》，约定原告向被告供电，被告按月交纳电费。2018年1月至6月，被告累计拖欠电费85万元。原告多次催交未果，于2018年7月对被告采取停电措施后诉至法院，要求被告支付拖欠电费及违约金。法院经审理查明，被告对拖欠电费85万元的事实无异议，但主张因经营困难请求减免。法院认为，供用电合同是供电人向用电人供电，用电人支付电费的合同。用电人应当按照国家有关规定和当事人的约定及时交付电费。被告拖欠电费构成违约，应当承担违约责任。判决被告支付原告电费85万元及按合同约定计算的违约金。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某房产中介诉刘某居间合同纠纷案', '某区基层人民法院', '{"cause": "合同纠纷", "court_level": "基层人民法院", "year": "2015", "summary": "原告为被告提供居间服务促成交易，被告拒付中介费。法院判决被告支付中介费。"}', '原告某房产中介公司与被告刘某于2019年3月签订《居间服务协议》，约定原告为被告购买二手房提供居间服务，被告在交易成功后支付中介费3万元。原告带被告看房多次后，被告看中一套房屋并签订购房合同。交易完成后，被告以中介费过高为由拒付。法院经审理查明，原告已按协议约定为被告提供了房源信息及带看服务，并促成被告与卖方签订房屋买卖合同。协议约定的中介费3万元符合当地市场行情。法院认为，居间人促成合同成立的，委托人应当按照约定支付报酬。原告已履行居间义务，被告应当支付中介费。判决被告支付原告中介费3万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某农业公司诉某超市买卖合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2015", "summary": "原告向被告供应农产品，被告以物流延迟致部分产品变质为由拒付货款。法院判决被告支付货款。"}', '原告某农业公司与被告某超市于2020年5月签订《农产品买卖合同》，约定原告向被告供应新鲜蔬菜，每周配送两次，月结货款。合同履行三个月后，被告以7月某次配送因物流延迟导致部分蔬菜变质为由，拒付当月全部货款12万元。法院经审理查明，该次配送延迟系因高速公路交通事故封路所致，延迟约6小时，部分叶菜确实出现变质，价值约8000元，其余蔬菜质量正常。被告已签收并上架销售。法院认为，买卖合同中因不可归责于双方的原因导致部分标的物损毁的，该部分货款可予扣除，但被告以部分货物变质为由拒付全部货款没有法律依据。判决被告支付原告货款11.2万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某建筑公司诉某材料公司买卖合同纠纷案', '某区基层人民法院', '{"cause": "合同纠纷", "court_level": "基层人民法院", "year": "2017", "summary": "原告向被告采购钢材，被告交付的钢材规格不符。法院判决被告更换货物并赔偿损失。"}', '原告某建筑公司与被告某材料公司于2017年4月签订《钢材买卖合同》，约定原告向被告采购某规格螺纹钢100吨，单价3800元每吨，总价38万元。被告交付货物后，原告在验货时发现钢材直径与合同约定不符，要求退货。被告以货物已交付且原告已签收为由拒绝。法院经审理查明，原告签收时在送货单上注明了对规格的异议，被告送货人员签字确认。经鉴定，交付的钢材直径偏差超出国家标准允许范围。法院认为，出卖人应当按照约定的质量要求交付标的物。交付的标的物不符合质量要求的，买受人可以要求承担违约责任。判决被告更换符合约定的钢材并赔偿原告停工损失2万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某设备租赁公司诉某施工企业租赁合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2015", "summary": "原告出租施工设备，被告使用后损坏设备且拖欠租金。法院判决被告支付租金及设备维修费。"}', '原告某设备租赁公司与被告某施工企业于2021年3月签订《设备租赁合同》，约定原告向被告出租塔吊一台，月租金3.5万元，租期6个月。被告使用至2021年7月后归还设备，累计拖欠租金14万元。归还的设备经检查发现主要结构变形、钢丝绳磨损严重，维修费用预估8万元。法院经审理查明，被告在使用过程中存在超负荷操作的情况，未尽到合理使用和保管义务。法院认为，承租人应当按照约定的方法使用租赁物，并妥善保管租赁物。承租人未妥善保管致使租赁物毁损的，应当承担损害赔偿责任。判决被告支付原告租金14万元及设备维修费8万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某软件公司诉某企业技术服务合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2015", "summary": "原告为被告开发ERP系统，被告以功能不全为由拒付尾款。法院判决被告支付尾款。"}', '原告某软件公司与被告某企业于2021年8月签订《ERP系统开发合同》，约定原告为被告开发企业资源管理系统，合同总价款120万元，分四期支付。原告完成系统开发并部署上线后，被告以库存模块功能不全为由拒付第四期尾款30万元。法院经审理查明，合同附件明确约定了库存模块的功能需求清单，原告已实现其中90%的功能，未实现的功能为非核心附加功能。被告已将系统投入实际使用达四个月。法院认为，技术服务合同的受托人已实质性完成合同义务，委托人已实际使用成果的，视为验收合格。判决被告支付原告尾款30万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某贸易公司诉某运输公司货物运输合同纠纷案', '某省高级人民法院', '{"cause": "合同纠纷", "court_level": "高级人民法院", "year": "2015", "summary": "原告委托被告运输进口货物，被告未按约定时间送达致原告违约。法院判决被告赔偿原告损失。"}', '原告某贸易公司与被告某运输公司于2019年6月签订《货物运输合同》，约定被告将原告进口的一批电子元件从港口运至某市仓库，运费8万元，约定交货期限为5天。被告因车辆调度问题延迟交货12天，导致原告无法按期向下游客户交货，被下游客户扣除违约金25万元。法院经审理查明，被告延迟交货系因其自身车辆调度不当，不存在不可抗力等免责事由。法院认为，承运人应当按照约定的期限将货物运送到目的地。承运人延迟运输的，应当承担违约责任。但约定的违约金过分高于实际损失的，可以适当减少。判决被告赔偿原告损失20万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某广告公司诉某集团承揽合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2015", "summary": "原告为被告制作广告宣传片，被告以效果不满意为由拒付尾款。法院判决被告支付尾款。"}', '原告某广告公司与被告某集团于2020年1月签订《广告制作合同》，约定原告为被告制作企业宣传片，合同总价款50万元，分期支付。原告按约定成拍摄和后期制作并交付成片，被告支付35万元后，以宣传片效果不符合预期为由拒付尾款15万元。法院经审理查明，合同中并未对宣传片的效果标准作出明确约定，原告交付的成片符合合同约定的技术规格和内容大纲。被告在制作过程中多次参与审片并提出修改意见，原告均已修改。法院认为，承揽人按定作人要求完成工作并交付工作成果的，定作人应当支付报酬。被告已参与审片并接受成片，应当支付尾款。判决被告支付原告尾款15万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '孙某诉某搬家公司运输合同纠纷案', '某区基层人民法院', '{"cause": "合同纠纷", "court_level": "基层人民法院", "year": "2018", "summary": "原告委托被告搬家，运输途中家具损坏。法院判决被告赔偿损失。"}', '原告孙某与被告某搬家公司于2018年5月签订搬家服务合同，约定被告为原告提供搬家运输服务，费用3000元。搬运过程中，被告工人因操作不当导致原告的红木衣柜严重损坏，维修费用评估为1.2万元。原告要求被告赔偿，被告以合同中约定最高赔偿额不超过运费三倍为由拒绝。法院经审理查明，合同中的赔偿限制条款系被告提供的格式条款，被告在签约时未采取合理方式提请原告注意。法院认为，格式条款免除提供方责任、限制对方主要权利的，该条款无效。承运人对运输过程中货物的毁损承担赔偿责任。判决被告赔偿原告家具损失1.2万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某建筑公司诉某水泥厂买卖合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2015", "summary": "原告长期向被告采购水泥，被告突然涨价未通知原告。法院判决涨价通知前已签订单按原价执行。"}', '原告某建筑公司与被告某水泥厂有长期合作关系，双方于2014年签订年度供货协议，约定水泥单价为每吨320元，供货量按月计划执行。2015年3月，被告因原材料成本上涨决定涨价至每吨380元，通过电子邮件通知原告。但原告在收到通知前已于3月10日下达了500吨的采购订单，被告按涨价后的价格发货并要求原告按新价付款。法院经审理查明，年度协议中约定价格调整需提前15天书面通知，被告3月15日发出通知，原告3月10日的订单应按原价执行。法院认为，合同当事人应当按照约定全面履行义务，价格调整应当遵循合同约定的程序。判决被告按原价320元每吨结算原告3月10日订单的货款。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某餐饮公司诉某商场租赁合同纠纷案', '某省高级人民法院', '{"cause": "合同纠纷", "court_level": "高级人民法院", "year": "2015", "summary": "原告承租商场商铺经营餐饮，商场改造施工影响经营。法院判决减免租金并赔偿损失。"}', '原告某餐饮公司与被告某商场于2021年签订《商铺租赁合同》，约定原告承租商场三楼商铺经营餐厅，年租金80万元。2022年3月至6月，商场对三楼进行大规模改造施工，搭建围挡、产生噪音和粉尘，导致原告餐厅客流大幅下降，月营业额下降60%。原告要求减免租金并赔偿损失，被告拒绝。法院经审理查明，商场改造施工确对原告经营造成重大影响，原告在此期间月营业额从25万元降至10万元。法院认为，出租人应当保证承租人对租赁物的正常使用。因出租人原因致使承租人无法正常使用租赁物的，承租人可以要求减少租金或者不支付租金。判决减免原告施工期间租金50%并赔偿经营损失10万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某机械公司诉某零件厂买卖合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2015", "summary": "原告向被告采购定制零件，被告交付产品不合格致原告整机退货。法院判决被告赔偿全部损失。"}', '原告某机械公司与被告某零件厂于2019年2月签订《定制零件买卖合同》，约定被告按原告提供的图纸生产某型号轴承座500件，单价200元。被告交付后，原告将零件组装至整机并交付客户。客户在使用过程中发现设备故障，经检测系轴承座材质不符合要求所致。客户将整机退回原告，原告损失包括货款、组装费、运费等共计35万元。法院经审理查明，被告交付的轴承座材质硬度低于图纸要求，系被告擅自更换原材料所致。法院认为，出卖人交付的标的物不符合质量要求的，买受人可以要求承担违约责任。被告交付不合格产品致原告遭受损失，应当承担赔偿责任。判决被告赔偿原告35万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某设计公司诉某地产公司技术服务合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2015", "summary": "原告为被告提供建筑设计服务，被告以设计未通过审批为由拒付设计费。法院判决被告支付设计费。"}', '原告某设计公司与被告某地产公司于2021年1月签订《建筑设计合同》，约定原告为被告某住宅项目提供建筑设计服务，设计费180万元，分阶段支付。原告按约定成方案设计并提交，被告支付前两阶段费用120万元后，以设计方案未通过规划审批为由拒付第三阶段设计费60万元。法院经审理查明，设计方案未通过审批系因被告在委托设计时提供的用地范围有误，导致设计方案超出用地红线。原告系按被告提供的基础资料进行设计，不存在过错。法院认为，委托人提供的基础资料有误致使工作成果不符合要求的，受托人不承担违约责任。判决被告支付原告设计费60万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某物流公司诉某电商公司运输合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2015", "summary": "原告为被告提供配送服务，被告以部分包裹丢失为由扣留全部运费。法院判决被告支付运费扣除丢失包裹赔偿后的余额。"}', '原告某物流公司与被告某电商公司于2023年签订《配送服务合同》，约定原告为被告提供城市配送服务，按月结算运费。2023年5月，被告以当月有15件包裹丢失为由，扣留全部运费28万元。法院经审理查明，当月原告共配送包裹5万件，确认丢失15件，丢失包裹内物品价值约3万元，丢失率在合同约定的合理损耗范围内。合同约定丢失率低于千分之一的，承运人不承担赔偿责任。法院认为，承运人已按约完成绝大部分配送义务，托运人以少量包裹丢失为由拒付全部运费没有法律依据。判决被告支付原告运费25万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '杨某诉某培训机构教育培训合同纠纷案', '某区基层人民法院', '{"cause": "合同纠纷", "court_level": "基层人民法院", "year": "2015", "summary": "原告为子女报名培训课程，机构停业致合同无法履行。法院判决退还预付学费。"}', '原告杨某与被告某培训机构于2022年1月签订《培训服务合同》，为原告子女报名一年期英语培训课程，预付学费2.8万元。2022年5月，被告因经营困难停止营业，未能提供后续培训服务。原告要求退还剩余学费，被告以资金困难为由拖延。法院经审理查明，被告已停止经营，无法继续提供培训服务，合同已无法履行。原告已上课4个月，剩余8个月课程未上，对应学费约1.9万元。法院认为，教育培训合同的培训机构停业致使合同目的无法实现的，消费者有权要求解除合同并退还预付费用。判决被告退还原告学费1.9万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某制造公司诉某供应商买卖合同纠纷案', '某省高级人民法院', '{"cause": "合同纠纷", "court_level": "高级人民法院", "year": "2015", "summary": "原告向被告采购原材料，被告迟延交货致原告停产。法院判决被告赔偿停产损失。"}', '原告某制造公司与被告某供应商于2024年1月签订《原材料采购合同》，约定被告向原告供应特种钢材200吨，交货期为2月15日。被告迟至3月10日才交货，导致原告因原材料断供停产20天，停产期间工人工资、设备折旧等固定成本损失45万元，利润损失30万元。法院经审理查明，被告迟延交货系因其将原告订购的原材料转卖给出价更高的第三方所致。法院认为，出卖人应当按照约定的时间交付标的物。出卖人迟延交货致买受人遭受损失的，应当承担赔偿责任。被告恶意违约，应当赔偿原告全部损失。判决被告赔偿原告75万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某装修公司诉周某承揽合同纠纷案', '某区基层人民法院', '{"cause": "合同纠纷", "court_level": "基层人民法院", "year": "2015", "summary": "原告为被告装修房屋，被告以装修质量有问题为由拒付尾款。法院判决被告支付尾款。"}', '原告某装修公司与被告周某于2022年10月签订《家庭装修合同》，约定原告为被告装修住宅一套，合同价款18万元，分期支付。原告完工后，被告以墙面漆面有裂纹为由拒付尾款4万元。法院经审理查明，墙面裂纹系房屋自身沉降所致，非装修施工质量问题。原告已按合同约定完成全部装修项目，被告已入住使用达三个月。法院认为，承揽人已完成工作成果并交付，定作人已实际使用的，视为验收合格。被告主张的质量问题非原告施工原因所致。判决被告支付原告尾款4万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某科技公司诉某通信公司技术服务合同纠纷案', '最高人民法院', '{"cause": "合同纠纷", "court_level": "最高人民法院", "year": "2025", "summary": "原告为被告开发通信软件，双方对技术标准产生争议。法院判决被告支付技术服务费。"}', '原告某科技公司与被告某通信公司于2024年3月签订《软件开发合同》，约定原告为被告开发5G通信管理软件，合同总价款500万元。原告完成开发并交付后，被告以软件在特定极端环境下的稳定性未达到行业标准为由拒付尾款200万元。经鉴定，软件在常温环境下的各项指标均符合合同约定，极端环境测试标准在合同中未作约定。法院认为，技术服务合同当事人对技术标准约定不明确的，应当按照合同目的和交易习惯确定。原告已实现合同主要目的，被告应当支付相应报酬。判决被告支付原告技术服务费200万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某贸易公司诉某仓储物流公司保管合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2018", "summary": "原告将进口商品存放在被告仓库，被告未经同意擅自搬动致商品损坏。法院判决被告赔偿损失。"}', '原告某贸易公司与被告某仓储物流公司于2018年3月签订《仓储保管合同》，约定被告为原告存放进口红酒200箱。4月，被告为腾出库房空间，未经原告同意将红酒转移至另一仓库，搬运过程中40箱红酒破损，损失12万元。法院经审理查明，合同明确约定保管场所为A库房，被告未经原告同意擅自转移保管场所并造成损失。法院认为，保管人应当妥善保管保管物，不得擅自改变保管场所。保管人擅自转移保管物造成毁损的，应当承担损害赔偿责任。判决被告赔偿原告12万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某建材公司诉某工程公司买卖合同纠纷案', '某区基层人民法院', '{"cause": "合同纠纷", "court_level": "基层人民法院", "year": "2016", "summary": "原告向被告供应瓷砖，被告以货物色差为由拒付货款。法院判决被告支付货款。"}', '原告某建材公司与被告某工程公司于2020年7月签订《瓷砖买卖合同》，约定原告向被告供应某型号瓷砖3000平方米，单价85元，总价25.5万元。被告收货后以瓷砖存在色差为由拒付货款。法院经审理查明，合同约定瓷砖为同一批次产品，原告交付的瓷砖经检测色差在国家标准允许范围内。被告已将大部分瓷砖铺贴使用。法院认为，标的物质量按照国家标准确定，色差在合理范围内的，不属于质量不合格。被告已实际使用标的物，应当支付货款。判决被告支付原告货款25.5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某设备公司诉某工厂承揽合同纠纷案', '某市中级人民法院', '{"cause": "合同纠纷", "court_level": "中级人民法院", "year": "2016", "summary": "原告为被告定制生产设备，被告以交货迟延为由解除合同。法院认定迟延系被告变更设计所致，判决继续履行。"}', '原告某设备公司与被告某工厂于2023年8月签订《设备定制合同》，约定原告为被告定制生产线设备一套，合同总价款280万元，交货期120天。施工期间，被告多次变更技术参数和设计要求，导致交货期顺延45天。原告于2024年1月完成设备交付，被告以迟延交货为由拒绝接收并要求解除合同。法院经审理查明，被告在合同履行期间先后提出7次设计变更，每次变更均导致工期顺延，累计顺延40天，原告实际迟延仅5天。法院认为，定作人变更工作要求致使工期延长的，工期相应顺延。原告迟延在合理范围内，不构成根本违约。判决合同继续履行，被告接收设备并支付尾款。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '张某诉某科技公司劳动合同解除纠纷案', '某区基层人民法院', '{"cause": "劳动争议", "court_level": "基层人民法院", "year": "2018", "summary": "原告张某被公司以末位淘汰为由解除劳动合同。法院认定末位淘汰不属于法定解除情形，判决公司支付赔偿金。"}', '原告张某于2016年7月入职被告某科技公司，担任软件工程师，月薪1.5万元。2018年3月，被告以张某在季度绩效考核中排名末位为由，单方解除劳动合同。张某认为末位淘汰不属于法定解除情形，要求被告支付违法解除劳动合同赔偿金。法院经审理查明，被告公司规章制度中虽有末位淘汰的规定，但该规定与劳动合同法相抵触。被告未提供证据证明张某不能胜任工作。法院认为，用人单位以末位淘汰为由解除劳动合同，不符合《劳动合同法》第三十九条、第四十条规定的解除条件，属于违法解除。判决被告支付原告违法解除劳动合同赔偿金6万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '李某诉某制造公司工资追索纠纷案', '某市中级人民法院', '{"cause": "劳动争议", "court_level": "中级人民法院", "year": "2016", "summary": "原告李某被公司拖欠工资六个月。法院判决公司支付拖欠工资及赔偿金。"}', '原告李某于2017年入职被告某制造公司，担任车间主任，月薪8000元。2018年9月起，被告以经营困难为由停止发放工资，至2019年2月累计拖欠工资4.8万元。李某多次催讨未果后离职并申请劳动仲裁，对仲裁裁决不服诉至法院。法院经审理查明，被告确实存在拖欠工资的事实，被告主张经营困难但未提供充分证据证明其经营状况严重恶化到无法支付工资的程度。法院认为，用人单位应当按照劳动合同约定和国家规定，向劳动者及时足额支付劳动报酬。拖欠工资的，应当支付拖欠工资及加付赔偿金。判决被告支付原告工资4.8万元及赔偿金2.4万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '王某诉某建筑公司工伤认定纠纷案', '某省高级人民法院', '{"cause": "劳动争议", "court_level": "高级人民法院", "year": "2016", "summary": "原告王某施工时受伤，公司以劳务关系为由拒绝工伤赔偿。法院认定存在劳动关系，判决工伤赔偿。"}', '原告王某于2019年3月经人介绍到被告某建筑公司工地从事木工工作，双方未签订书面劳动合同。2019年7月，王某在施工时从脚手架坠落受伤，造成右腿骨折。王某申请工伤认定，公司以双方系劳务关系为由否认劳动关系。法院经审理查明，王某在工地接受公司管理人员的指挥和安排，按月领取报酬，遵守公司考勤制度，双方存在事实劳动关系。法院认为，用人单位未与劳动者签订书面劳动合同，但存在事实劳动关系的，应当认定劳动关系成立。王某在施工中受伤，应当认定为工伤。判决被告支付原告工伤赔偿15万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '赵某诉某互联网公司竞业限制纠纷案', '某市中级人民法院', '{"cause": "劳动争议", "court_level": "中级人民法院", "year": "2016", "summary": "原告赵某离职后入职竞争对手，原公司要求支付竞业限制违约金。法院支持公司诉求。"}', '原告赵某于2018年入职被告某互联网公司，担任技术总监，年薪60万元。双方签订《竞业限制协议》，约定离职后两年内不得入职同行业竞争对手，公司每月支付竞业限制补偿金2万元，违反约定需支付违约金100万元。2020年6月赵某离职后，公司按月支付补偿金。2021年1月，赵某入职另一家互联网公司从事同类业务。公司发现后要求赵某支付违约金。法院经审理查明，赵某入职的新公司与被告存在直接竞争关系，赵某的行为违反了竞业限制协议。法院认为，竞业限制协议合法有效，劳动者违反竞业限制约定的，应当按照约定向用人单位支付违约金。判决赵某支付违约金100万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '陈某诉某餐饮公司社保争议纠纷案', '某区基层人民法院', '{"cause": "劳动争议", "court_level": "基层人民法院", "year": "2016", "summary": "原告陈某入职三年公司未缴社保。法院判决公司补缴社保费用。"}', '原告陈某于2016年5月入职被告某餐饮公司，担任厨师，月薪6000元。在职期间，被告未为陈某缴纳社会保险费。2019年3月陈某离职后，要求被告补缴在职期间的社会保险费。被告以陈某自愿放弃社保为由拒绝。法院经审理查明，被告在入职时让陈某签署了一份自愿放弃缴纳社保的声明，但该声明违反法律强制性规定。法院认为，依法参加社会保险是用人单位和劳动者的法定义务，不能通过协议免除。被告未依法为劳动者缴纳社会保险费的行为违法。判决被告为原告补缴在职期间的社会保险费。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '刘某诉某物流公司加班费纠纷案', '某市中级人民法院', '{"cause": "劳动争议", "court_level": "中级人民法院", "year": "2016", "summary": "原告刘某长期加班未获加班费。法院判决公司支付加班费。"}', '原告刘某于2020年入职被告某物流公司，担任配送员，月薪5000元。工作期间，刘某每天工作超过10小时，每周工作6天，但公司仅按基本工资支付，未支付任何加班费。刘某离职后要求公司支付在职期间加班费共计8万元。法院经审理查明，根据公司考勤记录和配送系统数据，刘某在职18个月期间累计加班超过2000小时，公司未支付加班费。法院认为，用人单位安排加班的，应当按照国家有关规定向劳动者支付加班费。工作日延长工作时间的支付不低于工资150%的报酬，休息日加班的支付不低于200%的报酬。判决被告支付原告加班费8万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '周某诉某贸易公司违法解除劳动合同纠纷案', '某区基层人民法院', '{"cause": "劳动争议", "court_level": "基层人民法院", "year": "2016", "summary": "原告周某在孕期被公司以精简人员为由解除合同。法院认定违法解除，判决恢复劳动关系并支付工资。"}', '原告周某于2018年入职被告某贸易公司，担任行政专员。2020年3月，周某怀孕五个月时，被告以公司精简人员为由解除与周某的劳动合同。周某认为被告违法解除劳动合同，要求恢复劳动关系。法院经审理查明，被告在解除合同时已知周某怀孕，所谓的精简人员仅针对周某一人，且未提前30日通知工会。法院认为，女职工在孕期、产期、哺乳期内，用人单位不得依照劳动合同法第四十条、第四十一条的规定解除劳动合同。被告的行为属于违法解除。判决恢复周某与被告的劳动关系，被告支付周某被违法解除期间的工资。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '吴某诉某电子公司未签订书面劳动合同纠纷案', '某市中级人民法院', '{"cause": "劳动争议", "court_level": "中级人民法院", "year": "2017", "summary": "原告吴某入职一年未签劳动合同。法院判决公司支付二倍工资差额。"}', '原告吴某于2016年4月入职被告某电子公司，担任质检员，月薪4500元。双方未签订书面劳动合同。2017年5月吴某离职后，要求被告支付未签订书面劳动合同期间的二倍工资差额。法院经审理查明，吴某入职后，被告一直未与吴某签订书面劳动合同，且未提供证据证明其曾主动要求签订而吴某拒绝。法院认为，用人单位自用工之日起超过一个月不满一年未与劳动者订立书面劳动合同的，应当向劳动者每月支付二倍的工资。判决被告支付原告二倍工资差额4.95万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '孙某诉某物业公司劳动争议纠纷案', '某区基层人民法院', '{"cause": "劳动争议", "court_level": "基层人民法院", "year": "2016", "summary": "原告孙某达到法定退休年龄后被公司辞退。法院认定劳动关系终止，但公司应支付经济补偿。"}', '原告孙某于2015年入职被告某物业公司，担任保安。2023年1月，孙某年满60周岁达到法定退休年龄，被告随即终止与孙某的劳动关系。孙某认为被告应当支付经济补偿金。法院经审理查明，孙某达到法定退休年龄后，不符合享受基本养老保险待遇的条件，无法领取养老金。法院认为，劳动者达到法定退休年龄的，劳动合同终止。但用人单位未为劳动者缴纳养老保险致其无法享受养老保险待遇的，用人单位应当给予适当补偿。判决被告支付原告经济补偿4万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某科技公司诉林某竞业限制纠纷案', '某市中级人民法院', '{"cause": "劳动争议", "court_level": "中级人民法院", "year": "2016", "summary": "原告公司起诉离职员工违反竞业限制。法院判决员工支付违约金并继续履行竞业限制义务。"}', '原告某科技公司与被告林某于2018年签订劳动合同，林某担任研发部经理，年薪40万元。双方签订竞业限制协议，约定离职后两年内不得从事同类业务，公司支付补偿金每月1.5万元，违约金80万元。2019年12月林某离职后，公司按月支付补偿金。2020年6月，公司发现林某以隐名股东方式参与设立了一家同行业公司。法院经审理查明，林某虽未直接入职竞争对手，但通过隐名投资方式参与同行业经营，实质上违反了竞业限制义务。法院认为，竞业限制义务不仅包括直接入职竞争对手，还包括以其他方式参与同行业经营。判决林某支付违约金80万元并继续履行竞业限制义务。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '黄某诉某工厂工伤待遇纠纷案', '某市中级人民法院', '{"cause": "劳动争议", "court_level": "中级人民法院", "year": "2016", "summary": "原告黄某工伤后公司未足额支付工伤待遇。法院判决公司补足差额。"}', '原告黄某于2018年在被告某工厂车间操作机器时被压伤右手，经鉴定为伤残八级。工伤保险基金支付了一次性伤残补助金，但被告未支付停工留薪期工资和一次性伤残就业补助金。黄某要求被告支付相关工伤待遇。法院经审理查明，黄某停工留薪期为6个月，被告在停工留薪期内仅按最低工资标准支付工资，未按原工资标准支付。黄某离职后，被告未支付一次性伤残就业补助金。法院认为，职工因工作遭受事故伤害需要暂停工作接受工伤医疗的，在停工留薪期内，原工资福利待遇不变。判决被告补足停工留薪期工资差额并支付一次性伤残就业补助金共计8万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '马某诉某集团公司经济补偿金纠纷案', '某省高级人民法院', '{"cause": "劳动争议", "court_level": "高级人民法院", "year": "2016", "summary": "原告马某在公司裁员中被解除合同，公司未按法定标准支付经济补偿。法院判决补足差额。"}', '原告马某于2012年入职被告某集团公司，2021年因公司经济性裁员被解除劳动合同。公司支付经济补偿金时，以马某的基本工资为计算基数，未将年终奖和绩效奖金计入。马某认为经济补偿金计算基数应包含全部收入。法院经审理查明，马某离职前12个月平均收入包括基本工资、绩效奖金和年终奖，月均收入1.2万元，但公司仅按基本工资6000元计算经济补偿。法院认为，计算经济补偿金的月工资是指劳动者在劳动合同解除前十二个月的平均应得工资，包括计时工资、计件工资、奖金、津贴等货币性收入。判决被告补足经济补偿金差额6万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '高某诉某外卖平台劳动关系确认纠纷案', '某市中级人民法院', '{"cause": "劳动争议", "court_level": "中级人民法院", "year": "2016", "summary": "原告高某为外卖平台配送员，要求确认与平台存在劳动关系。法院认定不存在劳动关系。"}', '原告高某于2021年在某外卖平台注册成为骑手，自主接单配送，按单结算。高某在配送过程中受伤，要求确认与平台存在劳动关系以申请工伤。法院经审理查明，高某自主决定上线时间和接单数量，不受平台考勤管理，可同时为多个平台配送。平台对骑手的管理主要是服务质量和配送时效方面的规范，不涉及劳动管理。法院认为，劳动关系的认定应当以用人单位对劳动者进行劳动管理为核心标准。高某与平台之间不存在人格从属性和经济从属性，不构成劳动关系。驳回高某的诉讼请求。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '郑某诉某教育机构未休年休假工资纠纷案', '某区基层人民法院', '{"cause": "劳动争议", "court_level": "基层人民法院", "year": "2016", "summary": "原告郑某工作五年未享受年休假。法院判决公司支付未休年休假工资。"}', '原告郑某于2018年入职被告某教育机构，担任教师。在职五年期间，被告以教学任务重为由从未安排郑某休年休假，也未支付未休年休假工资报酬。2023年郑某离职后要求被告支付未休年休假工资。法院经审理查明，郑某工作已满五年，依法享有每年5天带薪年休假。被告未安排郑某休年休假，也未支付相应报酬。法院认为，用人单位应当保证职工享受年休假。职工因工作原因未休年休假的，用人单位应当按照该职工日工资收入的300%支付年休假工资报酬。判决被告支付原告未休年休假工资1.5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '冯某诉某制造公司调岗降薪纠纷案', '某市中级人民法院', '{"cause": "劳动争议", "court_level": "中级人民法院", "year": "2024", "summary": "原告冯某被公司单方调岗降薪。法院判决调岗无效，恢复原岗位和薪资。"}', '原告冯某于2019年入职被告某制造公司，担任区域销售经理，月薪1.8万元。2024年1月，公司未经协商将冯某调至仓库管理员岗位，月薪降至6000元。冯某拒绝到新岗位报到，公司以其旷工为由解除劳动合同。法院经审理查明，劳动合同约定冯某的岗位为销售经理，公司调岗未经双方协商一致，且调岗理由不充分。公司以旷工为由解除劳动合同缺乏事实依据。法院认为，用人单位变更劳动合同约定的岗位和薪酬，应当与劳动者协商一致。单方调岗降薪不具有法律效力。判决恢复冯某原岗位和薪资待遇，被告支付调岗期间的工资差额。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '韩某诉某餐饮公司试用期违法解除纠纷案', '某区基层人民法院', '{"cause": "劳动争议", "court_level": "基层人民法院", "year": "2016", "summary": "原告韩某在试用期被以不符合录用条件为由辞退。法院认定公司未证明不符合录用条件，判决违法解除赔偿。"}', '原告韩某于2021年3月入职被告某餐饮公司，担任店长助理，试用期三个月。入职两个月后，公司以韩某不符合录用条件为由解除劳动合同。韩某认为公司未明确录用条件，解除行为违法。法院经审理查明，被告在招聘时未明确告知韩某具体的录用条件，也未提供考核标准和不胜任工作的证据。法院认为，用人单位以劳动者在试用期间被证明不符合录用条件为由解除劳动合同的，应当举证证明录用条件的具体内容以及劳动者不符合录用条件的事实。被告举证不足，解除行为违法。判决被告支付原告违法解除赔偿金。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '曹某诉某物业公司劳务派遣纠纷案', '某市中级人民法院', '{"cause": "劳动争议", "court_level": "中级人民法院", "year": "2016", "summary": "原告曹某系劳务派遣员工，用工单位退回后派遣公司不发工资。法院判决派遣公司支付工资。"}', '原告曹某于2019年与某劳务派遣公司签订劳动合同，被派遣至被告某物业公司担任保安。2020年4月，物业公司以曹某违反规章制度为由将其退回派遣公司。派遣公司在此后三个月内未安排曹某工作，也未支付工资。曹某要求派遣公司支付工资。法院经审理查明，曹某被退回派遣公司后，派遣公司未在合理期限内为其重新安排工作，也未支付工资。法院认为，劳务派遣单位是用人单位，应当履行用人单位对劳动者的义务。被派遣劳动者退回后在无工作期间，劳务派遣单位应当按照当地最低工资标准按月支付报酬。判决派遣公司支付曹某三个月工资。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '许某诉某科技公司年终奖纠纷案', '某省高级人民法院', '{"cause": "劳动争议", "court_level": "高级人民法院", "year": "2025", "summary": "原告许某离职后被公司拒发年终奖。法院判决公司支付年终奖。"}', '原告许某于2021年入职被告某科技公司。2024年12月，许某提出离职并于2025年1月正式离职。公司以许某离职时不在岗为由拒绝发放2024年度年终奖。法院经审理查明，公司年终奖制度规定年终奖根据全年绩效考核发放，许某2024年全年考核结果为合格，符合年终奖发放条件。公司制度中未规定离职员工不享受年终奖。法院认为，年终奖属于劳动报酬的组成部分，劳动者已提供全年劳动且符合年终奖发放条件的，用人单位应当支付。以离职为由拒发年终奖没有法律依据。判决被告支付原告2024年度年终奖5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '赵某诉钱某机动车交通事故责任纠纷案', '某区基层人民法院', '{"cause": "侵权责任", "court_level": "基层人民法院", "year": "2017", "summary": "被告钱某驾车闯红灯撞伤原告赵某。法院判决被告承担全部责任并赔偿各项损失。"}', '2017年5月，被告钱某驾驶轿车在某交叉路口闯红灯时，将正常通行的行人原告赵某撞伤。赵某被送医治疗，经诊断右腿胫骨骨折，住院治疗20天，花费医疗费3.5万元。交警部门认定钱某负事故全部责任。赵某诉至法院要求赔偿医疗费、误工费、护理费、营养费、交通费等共计8万元。法院经审理查明，钱某闯红灯系事故直接原因，应承担全部责任。赵某的医疗费3.5万元、误工费2万元、护理费5000元、营养费2000元、交通费1000元均有相应票据佐证。法院认为，机动车发生交通事故造成损害的，依照道路交通安全法承担赔偿责任。判决被告赔偿原告各项损失8万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '孙某诉某医院医疗损害责任纠纷案', '某市中级人民法院', '{"cause": "侵权责任", "court_level": "中级人民法院", "year": "2017", "summary": "原告孙某在被告医院手术中因医生过错致残。法院判决医院承担医疗损害赔偿责任。"}', '原告孙某因胆囊结石于2018年到被告某医院就诊，行腹腔镜胆囊切除术。术中，主刀医生操作失误损伤胆总管，导致孙某术后出现胆漏、腹腔感染等严重并发症，经再次手术修复。经鉴定，孙某构成九级伤残。孙某诉至法院要求医院赔偿医疗费、残疾赔偿金、精神损害抚慰金等共计50万元。法院经审理查明，术中胆总管损伤系主刀医生操作不当所致，存在医疗过错，且与孙某的损害后果存在因果关系。法院认为，患者在诊疗活动中受到损害，医疗机构及其医务人员有过错的，由医疗机构承担赔偿责任。判决被告赔偿原告45万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '周某诉某电器公司产品责任纠纷案', '某省高级人民法院', '{"cause": "侵权责任", "court_level": "高级人民法院", "year": "2017", "summary": "原告周某使用的被告生产的电热水器漏电致周某触电受伤。法院判决被告承担产品责任。"}', '原告周某于2019年购买被告某电器公司生产的电热水器一台。2020年1月，周某在洗澡时因热水器漏电触电受伤，造成右手电击伤及心律失常，住院治疗15天，花费医疗费5万元。经检测，热水器存在绝缘缺陷，系产品设计缺陷。周某诉至法院要求被告赔偿医疗费、误工费、精神损害抚慰金等共计20万元。法院经审理查明，涉案热水器经鉴定存在绝缘设计缺陷，漏电原因与产品设计缺陷存在因果关系。法院认为，因产品存在缺陷造成他人损害的，生产者应当承担侵权责任。判决被告赔偿原告18万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '吴某诉某网络公司网络侵权责任纠纷案', '某市中级人民法院', '{"cause": "侵权责任", "court_level": "中级人民法院", "year": "2017", "summary": "被告在其网站发布侵害原告名誉权的文章。法院判决被告删除文章并赔偿损失。"}', '原告吴某系某企业负责人。2021年3月，被告某网络公司在其运营的网站上发布一篇关于吴某的文章，其中包含吴某涉嫌商业欺诈、挪用资金等不实内容，被大量转发和评论，对吴某的名誉造成严重损害。吴某诉至法院要求被告删除文章、公开赔礼道歉并赔偿精神损害抚慰金。法院经审理查明，文章内容未经核实，其中关于吴某涉嫌犯罪的内容纯属捏造，被告作为网络信息服务提供者未尽到审核义务。法院认为，网络用户利用网络服务实施侵权行为的，被侵权人有权通知网络服务提供者采取删除、屏蔽等必要措施。判决被告删除侵权文章，在网站首页公开赔礼道歉30日，赔偿原告精神损害抚慰金5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某村委会诉某化工厂环境污染责任纠纷案', '某市中级人民法院', '{"cause": "侵权责任", "court_level": "中级人民法院", "year": "2018", "summary": "被告排放废水污染原告村内河流和农田。法院判决被告承担环境污染赔偿责任。"}', '原告某村委会所在村庄的河流和农田位于被告某化工厂下游。2017年以来，被告排放的工业废水未经充分处理即排入河流，导致河水污染、农作物减产，部分鱼类死亡。村委会代表村民诉至法院要求被告停止排污、治理污染并赔偿损失。法院经审理查明，被告排放的废水中重金属和化学需氧量严重超标，与河流污染和农作物损害存在因果关系。经评估，农田减产损失和渔业损失共计35万元。法院认为，污染者应当就法律规定的不承担责任或者减轻责任的情形及其行为与损害之间不存在因果关系承担举证责任。被告未能举证免责。判决被告停止超标排污，赔偿损失35万元，并承担环境修复费用。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '李某诉某小区业主高空抛物损害责任纠纷案', '某区基层人民法院', '{"cause": "侵权责任", "court_level": "基层人民法院", "year": "2017", "summary": "原告李某被小区高楼坠落的花盆砸伤。法院判决花盆所有人承担赔偿责任。"}', '原告李某于2022年3月经过某小区时，被从高楼坠落的花盆砸中头部，造成头部外伤和脑震荡，花费医疗费2万元。经调查，花盆系该楼8层住户王某阳台上摆放的花盆，因未固定被风吹落。李某诉至法院要求王某赔偿。法院经审理查明，王某在阳台外侧摆放花盆未采取固定措施，存在安全隐患。花盆坠落与李某受伤存在因果关系。法院认为，从建筑物中抛掷物品或者从建筑物上坠落的物品造成他人损害的，由侵权人依法承担侵权责任。王某作为花盆所有人未尽到安全管理义务。判决王某赔偿李某医疗费、误工费等共计3.5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '郑某诉某超市违反安全保障义务责任纠纷案', '某区基层人民法院', '{"cause": "侵权责任", "court_level": "基层人民法院", "year": "2017", "summary": "原告郑某在超市购物时因地面积水滑倒受伤。法院判决超市承担违反安全保障义务的赔偿责任。"}', '原告郑某于2019年6月在被告某超市购物时，因生鲜区地面有积水未及时清理而滑倒，导致右手腕骨折，花费医疗费1.5万元。郑某诉至法院要求超市赔偿。法院经审理查明，超市生鲜区地面确有积水，超市未设置警示标志，也未及时清理。法院认为，宾馆、商场、银行、车站、娱乐场所等公共场所的管理人或者群众性活动的组织者，未尽到安全保障义务，造成他人损害的，应当承担侵权责任。超市作为经营场所管理者，未及时清理地面积水，也未设置警示标志，存在过错。判决超市赔偿郑某医疗费、误工费等共计2.5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '陈某诉某教育培训机构教育机构责任纠纷案', '某市中级人民法院', '{"cause": "侵权责任", "court_level": "中级人民法院", "year": "2017", "summary": "原告陈某之子在培训机构上课时受伤。法院判决机构承担教育机构责任。"}', '原告陈某之子小陈（8岁）在被告某教育培训机构上体育课时，因教师疏于管理，小陈在攀爬训练中从器材上坠落，造成左臂骨折，花费医疗费2万元。陈某诉至法院要求培训机构赔偿。法院经审理查明，体育课教师未按规定在攀爬训练时进行一对一保护，且训练器材下方未铺设防护垫。法院认为，限制民事行为能力人在学校或者其他教育机构学习、生活期间受到人身损害，学校或者其他教育机构未尽到教育、管理职责的，应当承担责任。判决培训机构赔偿陈某医疗费、护理费等共计3.5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '王某诉某快递公司侵害隐私权纠纷案', '某市中级人民法院', '{"cause": "侵权责任", "court_level": "中级人民法院", "year": "2017", "summary": "被告快递员私自泄露原告快递信息。法院判决快递公司承担侵权责任。"}', '原告王某通过被告某快递公司寄送包含个人隐私信息的包裹。快递员张某在派送过程中私自拆开包裹，将王某的个人信息拍照并发布到社交媒体，导致王某频繁接到骚扰电话。王某诉至法院要求快递公司赔偿。法院经审理查明，快递员张某的行为系职务行为过程中发生，快递公司对员工管理和培训不到位。法院认为，自然人享有隐私权。任何组织或者个人不得以刺探、侵扰、泄露、公开等方式侵害他人的隐私权。用人单位的工作人员因执行工作任务造成他人损害的，由用人单位承担侵权责任。判决快递公司赔偿王某精神损害抚慰金2万元并赔礼道歉。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '杨某诉某建筑公司建筑物倒塌损害责任纠纷案', '某省高级人民法院', '{"cause": "侵权责任", "court_level": "高级人民法院", "year": "2017", "summary": "被告工地围墙倒塌砸伤原告杨某停放的车辆。法院判决建筑公司承担赔偿责任。"}', '原告杨某将其车辆停放在被告某建筑公司工地围墙外的道路旁。2021年4月，工地围墙因施工质量问题倒塌，砸毁杨某车辆，车辆维修费8万元。杨某诉至法院要求建筑公司赔偿。法院经审理查明，围墙倒塌系因施工方未按规范施工，墙基不牢固，且连日降雨导致地基松动。法院认为，建筑物、构筑物或者其他设施倒塌造成他人损害的，由建设单位与施工单位承担连带责任。被告作为施工单位，应当对围墙倒塌造成的损害承担赔偿责任。判决被告赔偿原告车辆维修费8万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '何某诉某宠物店饲养动物损害责任纠纷案', '某区基层人民法院', '{"cause": "侵权责任", "court_level": "基层人民法院", "year": "2017", "summary": "被告宠物店犬只逃出咬伤原告何某。法院判决宠物店承担饲养动物损害责任。"}', '原告何某于2022年5月经过被告某宠物店门口时，被告店内饲养的大型犬突然窜出，将何某扑倒并咬伤右腿，花费医疗费8000元，并造成何某心理恐惧。何某诉至法院要求宠物店赔偿。法院经审理查明，宠物店未对大型犬采取有效的约束措施，店门未关闭，犬只自行跑出。法院认为，饲养的动物造成他人损害的，动物饲养人或者管理人应当承担侵权责任。宠物店作为犬只的管理人，未尽到管理义务。判决宠物店赔偿何某医疗费、误工费、精神损害抚慰金等共计1.5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '林某诉某汽车厂家产品责任纠纷案', '某市中级人民法院', '{"cause": "侵权责任", "court_level": "中级人民法院", "year": "2017", "summary": "原告林某驾驶的被告生产的汽车刹车失灵致交通事故。法院判决厂家承担产品责任。"}', '原告林某于2019年购买被告某汽车厂家生产的轿车一辆。2020年3月，林某在正常行驶中因刹车失灵撞上前方车辆，造成林某及对方车辆人员受伤，两车损毁。经鉴定，刹车系统存在设计缺陷。林某诉至法院要求厂家赔偿车辆损失、医疗费等共计35万元。法院经审理查明，涉案车辆的刹车总泵存在设计缺陷，可能导致刹车失灵，厂家已对同批次车辆实施召回，但未通知林某。法院认为，因产品存在缺陷造成他人损害的，生产者应当承担侵权责任。判决厂家赔偿林某35万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '黄某诉某物业公司物业管理损害责任纠纷案', '某区基层人民法院', '{"cause": "侵权责任", "court_level": "基层人民法院", "year": "2017", "summary": "原告黄某家中因电梯故障被困受伤。法院判决物业公司承担赔偿责任。"}', '原告黄某于2023年1月乘坐小区电梯时，电梯突然从5楼急降至1楼，黄某在电梯内摔倒，造成腰椎压缩性骨折，花费医疗费3万元。黄某诉至法院要求物业公司赔偿。法院经审理查明，电梯急降系因电梯制动器老化失效，物业公司未按规定进行定期维护保养。法院认为，物业服务企业应当对小区公共设施进行维护管理，确保安全运行。物业公司未履行维护义务，致使电梯存在安全隐患造成损害，应当承担赔偿责任。判决物业公司赔偿黄某医疗费、误工费等共计5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '曾某诉某游乐场所违反安全保障义务责任纠纷案', '某市中级人民法院', '{"cause": "侵权责任", "court_level": "中级人民法院", "year": "2025", "summary": "原告曾某在游乐场乘坐过山车时受伤。法院判决游乐场承担赔偿责任。"}', '原告曾某于2021年7月在被告某游乐场所乘坐过山车时，因安全压杆松动从座位上滑出，造成肋骨骨折和软组织挫伤，花费医疗费4万元。曾某诉至法院要求游乐场赔偿。法院经审理查明，过山车安全压杆存在机械故障，游乐场在事发前已知晓但未及时维修，也未停止运营。法院认为，经营场所的经营者应当保证其提供的商品或者服务符合保障人身、财产安全的要求。游乐场明知设备存在安全隐患仍继续运营，存在重大过错。判决游乐场赔偿曾某医疗费、误工费、精神损害抚慰金等共计8万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '邓某诉某施工单位施工损害责任纠纷案', '某市中级人民法院', '{"cause": "侵权责任", "court_level": "中级人民法院", "year": "2025", "summary": "被告施工挖断地下管道致原告邓某房屋地基下沉。法院判决施工单位赔偿损失。"}', '原告邓某的房屋位于被告某施工单位道路改造工程附近。2019年4月，被告在施工中挖断了地下水管，大量漏水浸泡邓某房屋地基，导致房屋墙体开裂、地基不均匀沉降。邓某诉至法院要求施工单位赔偿房屋修复费用。法院经审理查明，被告施工前未充分勘察地下管线，施工中损坏水管导致邓某房屋受损。经鉴定，房屋修复费用25万元。法院认为，因施工行为造成他人财产损害的，施工单位应当承担侵权责任。判决被告赔偿邓某房屋修复费用25万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '丁某诉某汽车销售公司产品责任纠纷案', '某省高级人民法院', '{"cause": "侵权责任", "court_level": "高级人民法院", "year": "2024", "summary": "原告丁某购买的新车自燃。法院判决销售公司和厂家连带赔偿。"}', '原告丁某于2023年购买被告某汽车销售公司销售的轿车一辆。2024年2月，丁某在正常停放状态下车辆突然自燃，整车烧毁。消防部门认定起火原因为车辆电气系统故障。丁某诉至法院要求销售公司和厂家赔偿。法院经审理查明，车辆自燃系电气线路设计缺陷所致，属于产品缺陷。法院认为，因产品存在缺陷造成损害的，被侵权人可以向产品的生产者请求赔偿，也可以向产品的销售者请求赔偿。判决汽车厂家赔偿丁某车辆损失15万元及精神损害抚慰金1万元，销售公司承担连带责任。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '田某诉某健身俱乐部违反安全保障义务责任纠纷案', '某区基层人民法院', '{"cause": "侵权责任", "court_level": "基层人民法院", "year": "2025", "summary": "原告田某在健身时器械断裂致伤。法院判决俱乐部承担赔偿责任。"}', '原告田某于2022年在被告某健身俱乐部使用杠铃进行卧推训练时，杠铃杆突然断裂，砸伤田某胸部和面部，造成肋骨骨折和面部裂伤，花费医疗费3.5万元。田某诉至法院要求俱乐部赔偿。法院经审理查明，断裂的杠铃杆存在金属疲劳，已超过使用寿命，俱乐部未及时更换老化器材。法院认为，健身场所经营者应当确保器材安全可靠。俱乐部使用超过使用寿命的器材，未尽到安全保障义务。判决俱乐部赔偿田某医疗费、误工费等共计5.5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '方某诉某餐厅食物中毒损害责任纠纷案', '某区基层人民法院', '{"cause": "侵权责任", "court_level": "基层人民法院", "year": "2025", "summary": "原告方某在被告餐厅用餐后食物中毒。法院判决餐厅承担赔偿责任。"}', '原告方某于2023年8月在被告某餐厅用餐，食用海鲜后出现呕吐、腹泻等症状，经医院诊断为急性食物中毒，住院治疗5天，花费医疗费1.2万元。同日同餐厅用餐的多名顾客也出现类似症状。方某诉至法院要求餐厅赔偿。法院经审理查明，疾控中心调查报告认定食物中毒系餐厅供应的海鲜不新鲜且加工不当所致。法院认为，餐饮服务提供者应当保证食品安全。因食品安全问题造成消费者损害的，应当承担赔偿责任。判决餐厅赔偿方某医疗费、误工费等共计2万元，并支付价款十倍的赔偿金。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '王某诉李某离婚财产分割纠纷案', '某区基层人民法院', '{"cause": "婚姻家庭", "court_level": "基层人民法院", "year": "2017", "summary": "原告王某诉被告李某离婚，双方对婚后购房分割争议。法院判决房屋归女方所有，女方补偿男方份额。"}', '原告王某与被告李某于2012年登记结婚，婚后育有一子。2015年双方购买房屋一套，登记在王某名下，购房款80万元中50万元为王某父母出资，30万元为夫妻共同存款。2017年王某以感情破裂为由诉至法院要求离婚，双方对房屋分割存在争议。法院经审理查明，双方感情确已破裂，同意离婚。房屋购买时王某父母出资50万元部分应认定为对王某个人的赠与。法院认为，婚后由一方父母出资为子女购买的不动产，产权登记在出资人子女名下的，可按照合同法规定视为只对自己子女一方的赠与。判决房屋归王某所有，王某补偿李某房屋折价款15万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '张某诉赵某抚养权变更纠纷案', '某市中级人民法院', '{"cause": "婚姻家庭", "court_level": "中级人民法院", "year": "2025", "summary": "原告张某诉请变更子女抚养权。法院判决抚养权变更归原告。"}', '原告张某与被告赵某于2015年协议离婚，约定婚生子小张由赵某抚养。2018年起，赵某长期在外地工作，将小张交给年迈父母照看，疏于关心小张的学习和生活。张某诉至法院要求变更抚养权。法院经审理查明，赵某长期不在孩子身边，其父母年事已高难以充分照顾孩子。张某有稳定工作和住所，且孩子表示愿随张某生活。法院认为，变更抚养关系应当以有利于子女身心健康为原则。赵某客观上无法充分履行抚养义务，张某具备抚养条件且孩子愿意随其生活。判决变更抚养权归张某。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '陈某诉某遗嘱继承纠纷案', '某市中级人民法院', '{"cause": "婚姻家庭", "court_level": "中级人民法院", "year": "2025", "summary": "原告陈某与被告就遗产继承产生争议。法院按法定继承分割遗产。"}', '被继承人陈父于2019年去世，留有房屋一套和存款50万元。原告陈某系陈父长子，被告系陈父次子。陈父生前留有打印遗嘱一份，将房屋留给被告，存款由原告和被告平分。原告主张遗嘱无效，要求按法定继承。法院经审理查明，打印遗嘱仅有陈父签名，无见证人签名，不符合打印遗嘱的法定形式要件。法院认为，打印遗嘱应当有两个以上见证人在场见证，遗嘱人和见证人应当在遗嘱每一页签名。本案打印遗嘱不符合法定形式要件，应认定无效，按法定继承处理。判决房屋和存款由原告和被告各继承二分之一。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '刘某诉孙某夫妻共同债务纠纷案', '最高人民法院', '{"cause": "婚姻家庭", "court_level": "最高人民法院", "year": "2025", "summary": "债权人要求原告刘某承担前夫债务。法院判决该债务不属夫妻共同债务。"}', '原告刘某与被告孙某原系夫妻，2019年协议离婚。2020年，债权人起诉孙某偿还借款200万元，并主张该借款系孙某与刘某婚姻存续期间所借，属夫妻共同债务。刘某诉至法院请求确认该债务非夫妻共同债务。法院经审理查明，孙某所借200万元系用于其个人经营的公司资金周转，刘某未在借款合同上签字，事后未追认。借款金额远超家庭日常生活需要。法院认为，夫妻一方在婚姻存续期间以个人名义超出家庭日常生活需要所负的债务，不属于夫妻共同债务。判决该债务由孙某个人承担。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '周某诉吴某彩礼返还纠纷案', '某区基层人民法院', '{"cause": "婚姻家庭", "court_level": "基层人民法院", "year": "2018", "summary": "原告周某诉被告吴某返还彩礼。法院判决被告返还部分彩礼。"}', '原告周某与被告吴某于2017年经人介绍相识并订婚。周某向吴某家支付彩礼18万元及金首饰若干。双方未办理结婚登记即开始同居。2018年3月双方分手，周某要求吴某返还彩礼。法院经审理查明，双方未办理结婚登记但同居约六个月，彩礼中12万元用于双方同居期间共同生活支出。法院认为，当事人请求返还按照习俗给付的彩礼的，如果双方未办理结婚登记手续，人民法院应当予以支持。但应考虑共同生活时间、彩礼使用情况等因素。判决吴某返还周某彩礼8万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '郑某诉王某离婚及抚养费纠纷案', '某区基层人民法院', '{"cause": "婚姻家庭", "court_level": "基层人民法院", "year": "2025", "summary": "原告郑某诉被告王某离婚并要求支付抚养费。法院判决离婚并按月支付抚养费。"}', '原告郑某与被告王某于2014年结婚，育有一女。王某自2017年起长期在外地工作，每月仅寄回少量生活费，对家庭和子女疏于照顾。郑某以夫妻感情破裂为由诉至法院要求离婚，并要求王某每月支付抚养费3000元。法院经审理查明，双方分居已超过两年，夫妻感情确已破裂。王某月收入约8000元。法院认为，离婚后子女由一方抚养的，另一方应负担必要的生活费和教育费。根据子女实际需要和父母负担能力，判决王某每月支付抚养费2000元至女儿成年。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '钱某诉赵某离婚后财产纠纷案', '某市中级人民法院', '{"cause": "婚姻家庭", "court_level": "中级人民法院", "year": "2021", "summary": "原告钱某发现前夫赵某离婚时隐瞒财产。法院判决重新分割隐瞒的财产。"}', '原告钱某与被告赵某于2019年协议离婚，双方对共同财产进行了分割。2021年，钱某发现赵某在离婚时隐瞒了其名下一处商铺和股票账户内的资金共计120万元。钱某诉至法院要求重新分割该部分财产。法院经审理查明，赵某在离婚时确实未披露上述财产，存在隐瞒夫妻共同财产的行为。法院认为，离婚后一方发现另一方隐瞒夫妻共同财产的，可以向人民法院提起诉讼请求再次分割夫妻共同财产。对隐瞒一方可以少分或不分。判决赵某分得30万元，钱某分得90万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '孙某诉李某赡养费纠纷案', '某区基层人民法院', '{"cause": "婚姻家庭", "court_level": "基层人民法院", "year": "2022", "summary": "原告孙某诉子女李某支付赡养费。法院判决李某按月支付赡养费。"}', '原告孙某年逾七十，退休金每月2000元，患有高血压和糖尿病，每月医疗费用约1500元。被告李某系孙某之子，月收入6000元，但长期不看望孙某也不支付赡养费。孙某诉至法院要求李某每月支付赡养费2000元。法院经审理查明，孙某退休金不足以支付生活及医疗费用，李某有赡养能力但不履行赡养义务。法院认为，成年子女对父母负有赡养义务。子女不履行赡养义务时，无劳动能力的或生活困难的父母，有要求子女付给赡养费的权利。判决李某每月支付孙某赡养费1500元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '吴某诉郑某离婚纠纷案', '某市中级人民法院', '{"cause": "婚姻家庭", "court_level": "中级人民法院", "year": "2020", "summary": "原告吴某诉被告郑某离婚，被告不同意。法院认定感情破裂判决离婚。"}', '原告吴某与被告郑某于2013年结婚。2018年起，双方因感情不和开始分居。2019年吴某第一次起诉离婚被驳回。2020年吴某再次起诉离婚，郑某不同意离婚。法院经审理查明，双方分居已满两年，经法院调解和好无效。法院认为，因感情不和分居满二年，经调解无效的，应准予离婚。吴某曾起诉离婚被驳回后双方仍分居，夫妻感情确已破裂。判决准予离婚。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '冯某诉陈某探望权纠纷案', '某区基层人民法院', '{"cause": "婚姻家庭", "court_level": "基层人民法院", "year": "2023", "summary": "原告冯某诉被告陈某阻挠其探望子女。法院判决原告享有探望权。"}', '原告冯某与被告陈某于2021年离婚，婚生子由陈某抚养。离婚后陈某以冯某不支付抚养费为由拒绝冯某探望子女。冯某诉至法院要求行使探望权。法院经审理查明，冯某确实存在拖欠抚养费的情况，但陈某不能以此为由阻挠探望。法院认为，离婚后不直接抚养子女的父或母有探望子女的权利，另一方有协助的义务。抚养费的支付与探望权的行使是两个独立的法律关系，不能以不支付抚养费为由拒绝探望。判决冯某每月可探望子女两次，陈某应予以协助。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '蒋某诉韩某离婚损害赔偿纠纷案', '某市中级人民法院', '{"cause": "婚姻家庭", "court_level": "中级人民法院", "year": "2021", "summary": "原告蒋某诉被告韩某离婚并要求损害赔偿。法院支持损害赔偿请求。"}', '原告蒋某与被告韩某于2015年结婚。2020年蒋某发现韩某与第三人保持不正当关系并同居。蒋某诉至法院要求离婚并要求韩某赔偿精神损害抚慰金。法院经审理查明，韩某在婚姻存续期间与他人同居，存在重大过错。法院认为，有下列情形之一导致离婚的，无过错方有权请求损害赔偿：与他人同居的。韩某的行为严重伤害夫妻感情，蒋某作为无过错方有权请求损害赔偿。判决准予离婚，韩某赔偿蒋某精神损害抚慰金5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '沈某诉杨某确认收养关系纠纷案', '某市中级人民法院', '{"cause": "婚姻家庭", "court_level": "中级人民法院", "year": "2019", "summary": "原告沈某诉请确认与被告杨某的收养关系。法院认定收养关系成立。"}', '原告沈某于2005年收养弃婴杨某并抚养长大，但未办理收养登记手续。2019年杨某已满14岁，沈某诉至法院要求确认收养关系。法院经审理查明，沈某无子女，具备抚养教育能力，已实际抚养杨某14年，杨某愿继续与沈某共同生活。法院认为，收养应当向县级以上人民政府民政部门登记，收养关系自登记之日起成立。沈某虽未办理登记，但已实际抚养杨某多年，且符合收养条件，应当补办登记。判决沈某与杨某应在判决生效后补办收养登记手续。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '朱某诉何某离婚后损害赔偿纠纷案', '某区基层人民法院', '{"cause": "婚姻家庭", "court_level": "基层人民法院", "year": "2024", "summary": "原告朱某离婚后发现前夫何某离婚前转移财产。法院判决何某赔偿。"}', '原告朱某与被告何某于2022年协议离婚。2023年朱某发现何某在离婚前一个月将其名下股票账户内50万元转移至其母亲账户。朱某诉至法院要求何某赔偿。法院经审理查明，何某在离婚前将夫妻共同财产50万元转移至案外人账户，属于隐藏、转移夫妻共同财产的行为。法院认为，离婚时一方隐藏、转移夫妻共同财产的，分割夫妻共同财产时可以少分或不分。离婚后发现上述行为的，可以向人民法院提起诉讼请求再次分割。判决何某赔偿朱某40万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '秦某诉许某变更抚养关系纠纷案', '某市中级人民法院', '{"cause": "婚姻家庭", "court_level": "中级人民法院", "year": "2022", "summary": "原告秦某诉请变更子女抚养权。法院因被告患病判决变更。"}', '原告秦某与被告许某于2018年离婚，婚生女由许某抚养。2021年许某被诊断为重度抑郁症，多次住院治疗，无法照顾女儿。秦某诉至法院要求变更抚养权。法院经审理查明，许某患有重度抑郁症，需长期治疗，客观上无力抚养子女。秦某有稳定工作和住所。法院认为，与子女共同生活的一方因患严重疾病或因伤残无力继续抚养子女的，另一方可以要求变更抚养关系。判决变更抚养权归秦某。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '吕某诉施某离婚财产分割纠纷案', '某省高级人民法院', '{"cause": "婚姻家庭", "court_level": "高级人民法院", "year": "2025", "summary": "原告吕某诉被告施某离婚，双方对公司股权分割争议。法院判决股权归男方，男方补偿女方。"}', '原告吕某与被告施某于2010年结婚。施某于2012年投资设立某公司，持股60%。2024年吕某起诉离婚，要求分割施某持有的公司股权。法院经审理查明，该股权系婚姻存续期间取得，属于夫妻共同财产。公司其他股东表示不行使优先购买权。法院认为，婚姻存续期间以夫妻共同财产投资取得的股权属于夫妻共同财产。考虑到公司经营管理的连续性，判决股权归施某所有，施某按股权评估价值的50%补偿吕某。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '孔某诉曹某婚约财产纠纷案', '某区基层人民法院', '{"cause": "婚姻家庭", "court_level": "基层人民法院", "year": "2016", "summary": "原告孔某诉被告曹某返还婚约彩礼。法院判决返还大部分彩礼。"}', '原告孔某与被告曹某于2015年订婚，孔某向曹某支付彩礼15万元及金首饰价值5万元。双方办理了结婚登记但未举行婚礼即因矛盾分居。2016年孔某起诉离婚并要求返还彩礼。法院经审理查明，双方已办理结婚登记但共同生活时间极短，彩礼数额较大。法院认为，当事人请求返还彩礼的，如果双方办理结婚登记手续但确未共同生活的，人民法院应当予以支持。双方虽登记但共同生活时间极短，应酌情返还。判决曹某返还孔某彩礼12万元及金首饰。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '严某诉魏某遗产分割纠纷案', '某市中级人民法院', '{"cause": "婚姻家庭", "court_level": "中级人民法院", "year": "2024", "summary": "原告严某诉被告魏某分割父母遗产。法院按法定继承分割。"}', '被继承人严父、严母于2023年先后去世，未留遗嘱。遗产包括房屋两套和存款120万元。原告严某系长女，被告魏某系次女。严某主张父母生前口头表示房屋归其所有，要求房屋归自己。法院经审理查明，严某未能提供有效证据证明父母留有口头遗嘱。法院认为，继承开始后，没有遗嘱的，按法定继承办理。同一顺序继承人继承遗产的份额一般应当均等。判决两套房屋和120万存款由严某和魏某各继承二分之一。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '华某诉方某离婚及夫妻共同债务承担纠纷案', '某区基层人民法院', '{"cause": "婚姻家庭", "court_level": "基层人民法院", "year": "2018", "summary": "原告华某诉被告方某离婚并确认债务承担。法院判决离婚并分担共同债务。"}', '原告华某与被告方某于2013年结婚。2017年方某以个人名义借款30万元用于家庭购房装修。2018年华某起诉离婚，双方对30万元借款的承担产生争议。法院经审理查明，该30万元借款用于家庭共同生活，属于夫妻共同债务。法院认为，离婚时原为夫妻共同生活所负的债务应当共同偿还。判决准予离婚，30万元共同债务由华某和方某各承担15万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '贺某诉某房产中介房屋买卖合同纠纷案', '某区基层人民法院', '{"cause": "房产纠纷", "court_level": "基层人民法院", "year": "2015", "summary": "原告通过中介购买二手房，中介隐瞒房屋漏水情况。法院判决中介退还中介费并赔偿损失。"}', '原告贺某于2014年10月通过被告某房产中介购买二手房一套。被告在带看房屋时表示房屋状况良好。原告入住后发现房屋存在严重漏水问题，墙面发霉。经了解，漏水问题在出售前已存在，被告明知但未告知原告。法院经审理查明，被告作为中介已从前业主处得知漏水问题但未如实告知。原告修复漏水花费3.5万元。法院认为，中介机构应当如实报告房屋状况，故意隐瞒重要事实的应当承担赔偿责任。判决被告退还中介费2万元并赔偿维修费3.5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某业主委员会诉某物业公司物业服务合同纠纷案', '某市中级人民法院', '{"cause": "房产纠纷", "court_level": "中级人民法院", "year": "2017", "summary": "业委会起诉物业公司服务不达标。法院判决物业公司退还部分物业费并整改。"}', '某小区业主委员会代表全体业主起诉被告某物业公司，主张物业公司未按合同约定提供服务，小区环境脏乱、电梯频繁故障、安保人员不足。法院经审理查明，物业公司确实存在绿化养护不到位、电梯维修不及时、保安配置不足等违约行为。法院认为，物业服务企业应当按照合同约定提供相应的服务。未达到约定服务标准的，应当承担违约责任。判决物业公司退还业主部分物业费15万元并限期整改。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '吴某诉某开发商商品房买卖合同纠纷案', '某市中级人民法院', '{"cause": "房产纠纷", "court_level": "中级人民法院", "year": "2018", "summary": "原告吴某购买的商品房逾期交房。法院判决开发商支付逾期交房违约金。"}', '原告吴某于2016年与被告某开发商签订《商品房买卖合同》，购买住宅一套，总价120万元，约定交房日期为2017年6月30日。被告至2018年1月才交房，逾期180天。合同约定逾期交房按日支付已付房价万分之五的违约金。法院经审理查明，被告逾期交房系因其自身资金链断裂导致工程停工，不存在不可抗力事由。法院认为，开发商应当按照约定时间交付房屋，逾期交付的应当按约支付违约金。判决被告支付原告逾期交房违约金10.8万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '陈某诉某开发商商品房质量问题纠纷案', '某区基层人民法院', '{"cause": "房产纠纷", "court_level": "基层人民法院", "year": "2019", "summary": "原告陈某购买的商品房墙体开裂。法院判决开发商承担保修责任并赔偿损失。"}', '原告陈某于2017年购买被告某开发商开发的商品房一套，2018年装修入住后发现多个房间墙体出现裂缝，客厅天花板出现渗水。经鉴定，墙体裂缝系施工质量不合格所致。法院经审理查明，房屋尚在保修期内，质量问题系施工缺陷所致。法院认为，开发商应当对房屋质量承担保修责任。判决被告免费修复墙体裂缝和渗水问题，并赔偿原告因维修期间的租房费用1.5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '林某诉邻居相邻关系纠纷案', '某区基层人民法院', '{"cause": "房产纠纷", "court_level": "基层人民法院", "year": "2020", "summary": "原告林某诉邻居在公共走廊堆放杂物影响通行。法院判决邻居清除杂物。"}', '原告林某与被告系同楼层邻居。被告长期在公共走廊堆放鞋柜、纸箱等杂物，占用公共通道，影响林某通行和消防安全。林某多次交涉未果后诉至法院。法院经审理查明，被告在公共走廊堆放杂物的事实清楚，存在安全隐患。法院认为，不动产的相邻权利人应当按照有利生产、方便生活、团结互助、公平合理的原则正确处理相邻关系。被告侵占公共通道堆放杂物的行为侵害了原告的合法权益。判决被告限期清除走廊杂物。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '赵某诉某装修公司装饰装修合同纠纷案', '某市中级人民法院', '{"cause": "房产纠纷", "court_level": "中级人民法院", "year": "2021", "summary": "原告赵某委托被告装修房屋，被告施工质量不合格。法院判决返工并赔偿。"}', '原告赵某与被告某装修公司于2020年签订装修合同，约定被告为原告装修住宅，价款15万元。装修完成后原告发现墙面不平、地砖空鼓、水电管线不合规等问题。经鉴定，装修质量不符合国家标准。法院经审理查明，被告施工确实存在多项质量不合格问题。法院认为，承揽人交付的工作成果不符合质量要求的，定作人可以要求承揽人承担返修、重作等违约责任。判决被告免费返修不合格项目并赔偿原告损失2万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某业主诉某开发商车位买卖合同纠纷案', '某区基层人民法院', '{"cause": "房产纠纷", "court_level": "基层人民法院", "year": "2022", "summary": "原告购买的车位尺寸不符合约定。法院判决开发商更换车位并赔偿。"}', '原告于2021年向被告某开发商购买地下车位一个，价款12万元。交付后发现车位尺寸宽度仅2.2米，远低于合同约定的2.5米，无法正常停放车辆。法院经审理查明，车位实际尺寸确实不符合合同约定。法院认为，出卖人交付的标的物不符合约定的，买受人可以要求更换。判决开发商为原告更换符合约定的车位并赔偿差价。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '黄某诉某房产公司二手房交易纠纷案', '某市中级人民法院', '{"cause": "房产纠纷", "court_level": "中级人民法院", "year": "2019", "summary": "原告黄某购买二手房后发现房屋为凶宅。法院判决撤销合同并赔偿。"}', '原告黄某于2018年通过被告某房产公司居间购买二手房一套，入住后从邻居处得知前业主曾在屋内自杀身亡。黄某认为卖方和中介隐瞒重要信息，诉至法院要求撤销合同。法院经审理查明，卖方和中介明知房屋内发生过非正常死亡事件但未告知买方。法院认为，一方以欺诈手段使对方在违背真实意思的情况下订立的合同，受损害方有权请求撤销。判决撤销房屋买卖合同，卖方退还购房款，中介退还中介费。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '刘某诉某物业公司物业服务费纠纷案', '某区基层人民法院', '{"cause": "房产纠纷", "court_level": "基层人民法院", "year": "2023", "summary": "原告刘某拒交物业费被物业起诉。法院判决业主支付物业费但减免部分费用。"}', '原告刘某系某小区业主，因小区电梯频繁故障、安保不到位等问题拒绝交纳物业费2年。物业公司起诉要求刘某支付拖欠物业费8000元及滞纳金。法院经审理查明，物业公司确实存在服务不到位的情形，但业主不能以此为由完全拒交物业费。法院认为，业主应当按约定交纳物业费。物业公司服务不达标的，可以酌情减免物业费。判决刘某支付物业费6000元，驳回物业公司滞纳金请求。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '张某诉某开发商广告宣传纠纷案', '某市中级人民法院', '{"cause": "房产纠纷", "court_level": "中级人民法院", "year": "2020", "summary": "原告张某诉开发商未兑现广告中的配套承诺。法院判决开发商赔偿。"}', '原告张某于2018年购买被告某开发商楼盘房屋，开发商在广告中宣传小区将配建幼儿园和会所，但交房后一直未建设。张某等业主诉至法院要求开发商履行承诺。法院经审理查明，开发商广告中对幼儿园和会所的描述具体明确，对合同订立和房屋价格有重大影响，应当视为要约。法院认为，商品房的销售广告和宣传资料为要约邀请，但出卖人就商品房开发规划范围内的房屋及相关设施所作的说明和允诺具体确定，并对合同订立和房屋价格有重大影响的，应当视为要约。判决开发商赔偿业主损失共计30万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '王某诉李某房屋买卖合同纠纷案', '某区基层人民法院', '{"cause": "房产纠纷", "court_level": "基层人民法院", "year": "2021", "summary": "原告王某购买房屋后卖方拒绝过户。法院判决继续履行合同。"}', '原告王某与被告李某于2020年签订房屋买卖合同，约定李某将房屋出售给王某，价款200万元。王某支付定金40万元后，李某以房价上涨为由拒绝过户。法院经审理查明，双方签订的买卖合同合法有效，王某已按约支付定金。法院认为，当事人应当按照约定全面履行义务。李某单方拒绝履行合同构成违约。判决李某继续履行合同，协助办理过户手续，并承担违约金。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某小区业委会诉某开发商车位权属纠纷案', '某省高级人民法院', '{"cause": "房产纠纷", "court_level": "高级人民法院", "year": "2022", "summary": "业委会诉请确认小区地下车位归全体业主。法院判决部分车位归业主共有。"}', '某小区业委会起诉开发商，主张小区地下人防车位和部分规划车位应归全体业主所有。开发商主张其拥有车位产权。法院经审理查明，涉案车位中，人防工程改造的车位未计入公摊面积但属人防工程，规划车位中部分计入公摊面积。法院认为，建筑区划内规划用于停放汽车的车位、车库的归属由当事人通过出售、附赠或出租等方式约定。但人防工程车位和计入公摊面积的车位属全体业主共有。判决人防车位和公摊车位归全体业主所有。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '孙某诉某开发商面积差异纠纷案', '某市中级人民法院', '{"cause": "房产纠纷", "court_level": "中级人民法院", "year": "2019", "summary": "原告孙某购买房屋实际面积小于约定。法院判决开发商退还差价。"}', '原告孙某于2018年购买被告某开发商商品房，合同约定面积120平方米。交房后实测面积为114平方米，面积误差比绝对值达5%。法院经审理查明，面积误差超过3%。法院认为，面积误差比绝对值超出3%的，买受人有权退房或要求出卖人承担违约责任。判决开发商退还面积差价款10万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '周某诉邻居噪音扰民相邻关系纠纷案', '某区基层人民法院', '{"cause": "房产纠纷", "court_level": "基层人民法院", "year": "2023", "summary": "原告周某诉楼上邻居深夜噪音扰民。法院判决邻居采取隔音措施。"}', '原告周某与被告系上下楼邻居。被告经常在深夜制造噪音，影响周某家人休息。周某多次协商无果后诉至法院。法院经审理查明，经环保部门检测，被告家中夜间噪音超过国家标准。法院认为，不动产相邻权利人不得违规排放噪声影响他人。判决被告在卧室铺设隔音地板，限制夜间活动噪音。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某业主诉某物业公司电梯更换纠纷案', '某市中级人民法院', '{"cause": "房产纠纷", "court_level": "中级人民法院", "year": "2024", "summary": "业主诉物业公司拒绝更换老旧电梯。法院判决动用维修基金更换电梯。"}', '某小区电梯已使用18年，频繁故障，存在安全隐患。业主提议动用维修基金更换电梯，物业公司以程序复杂为由拖延。法院经审理查明，电梯已超过设计使用年限，存在安全隐患，经特种设备检验机构建议更换。法院认为，住宅专项维修资金用于住宅共用部位、共用设施设备保修期满后的维修和更新改造。判决物业公司启动维修基金更换电梯程序。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '马某诉某开发商精装修房质量纠纷案', '某区基层人民法院', '{"cause": "房产纠纷", "court_level": "基层人民法院", "year": "2021", "summary": "原告马某购买精装修房发现甲醛超标。法院判决开发商治理并赔偿。"}', '原告马某于2020年购买被告某开发商精装修商品房，入住后家人出现身体不适。经检测，室内甲醛含量超标。法院经审理查明，精装修房使用的板材和胶水不达标导致甲醛超标。法院认为，开发商交付的精装修房应当符合室内环境质量标准。判决开发商承担甲醛治理费用并赔偿马某租房费用2万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '高某诉某二手房卖家隐瞒房屋质量问题纠纷案', '某市中级人民法院', '{"cause": "房产纠纷", "court_level": "中级人民法院", "year": "2022", "summary": "原告高某购买二手房后发现承重墙被拆改。法院判决撤销合同。"}', '原告高某于2021年购买被告二手房一套。装修时发现房屋承重墙被前业主拆改，存在结构安全隐患。高某诉至法院要求撤销合同。法院经审理查明，被告在出售时明知承重墙被拆改但未告知。法院认为，卖方隐瞒影响房屋安全的重要信息构成欺诈。判决撤销合同，被告退还购房款并赔偿高某交易费用损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某业主委员会诉某物业公司账目公开纠纷案', '某区基层人民法院', '{"cause": "房产纠纷", "court_level": "基层人民法院", "year": "2025", "summary": "业委会诉物业公司公开收支账目。法院判决物业公司公开账目。"}', '某小区业委会要求被告某物业公司公开上年度物业费收支明细和公共收益账目，物业公司以商业秘密为由拒绝。法院经审理查明，业委会有权监督物业公司的收支情况。法院认为，业主对物业共用部位、共用设施设备和相关场地使用情况享有知情权和监督权。判决物业公司向业委会公开上年度物业费收支明细和公共收益账目。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '赵某诉钱某民间借贷纠纷案', '某区基层人民法院', '{"cause": "借贷纠纷", "court_level": "基层人民法院", "year": "2018", "summary": "原告赵某借给被告钱某20万元，被告逾期未还。法院判决偿还本金及利息。"}', '原告赵某于2017年6月借给被告钱某20万元，约定借期一年，年利率18%。钱某出具借条。借款到期后钱某以经营亏损为由拒绝还款。法院经审理查明，借贷关系有借条和银行转账记录佐证，钱某对借款事实无异议。法院认为，合法的借贷关系受法律保护。年利率18%未超过法律规定的上限。判决钱某偿还赵某本金20万元及利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某投资公司诉某P2P平台借款合同纠纷案', '某市中级人民法院', '{"cause": "借贷纠纷", "court_level": "中级人民法院", "year": "2019", "summary": "原告通过P2P平台出借资金，平台爆雷后追索借款人。法院判决借款人偿还。"}', '原告某投资公司通过某P2P平台向被告孙某出借资金10万元，约定年利率15%。借款到期后孙某未还款，平台已爆雷无法协助催收。原告直接起诉孙某。法院经审理查明，借款合同系双方真实意思表示，原告已通过平台向孙某交付借款。法院认为，P2P平台作为中介撮合出借人与借款人直接形成借贷关系，平台爆雷不影响借贷合同的效力。判决孙某偿还原告本金10万元及利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某银行诉刘某信用卡纠纷案', '某区基层人民法院', '{"cause": "借贷纠纷", "court_level": "基层人民法院", "year": "2020", "summary": "被告刘某信用卡透支拒不还款。法院判决偿还透支本金及利息。"}', '被告刘某在原告某银行办理信用卡一张，信用额度5万元。2019年起刘某大量透支后拒不还款，累计欠款本金4.5万元、利息及违约金1.2万元。银行多次催收无果后诉至法院。法院经审理查明，刘某的透支行为有交易记录为证。法院认为，信用卡持卡人应当按约定偿还透支款。判决刘某偿还透支本金4.5万元及按合同约定计算的利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某担保公司诉某企业担保追偿权纠纷案', '某市中级人民法院', '{"cause": "借贷纠纷", "court_level": "中级人民法院", "year": "2021", "summary": "原告担保公司代偿后向借款人追偿。法院判决借款人偿还代偿款。"}', '被告某企业向银行借款500万元，由原告某担保公司提供连带保证担保。借款到期后某企业未还款，担保公司代偿本息520万元。担保公司向某企业追偿未果后诉至法院。法院经审理查明，担保公司已实际代偿520万元。法院认为，保证人承担保证责任后有权向债务人追偿。判决某企业偿还担保公司代偿款520万元及资金占用费。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '王某诉某小贷公司高利贷纠纷案', '某区基层人民法院', '{"cause": "借贷纠纷", "court_level": "基层人民法院", "year": "2019", "summary": "原告王某向被告借款，被告收取高额利息。法院认定超过法定上限部分无效。"}', '原告王某于2018年向被告某小贷公司借款5万元，约定月利率5%（年利率60%），借期6个月。王某按约支付3个月利息后无力支付。小贷公司起诉要求偿还本金及利息。法院经审理查明，双方约定的年利率60%远超过法律规定的上限。法院认为，借贷双方约定的利率未超过年利率24%的受法律保护，超过36%的部分无效。判决王某偿还本金5万元及按年利率24%计算的利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '李某诉周某民间借贷纠纷案', '某区基层人民法院', '{"cause": "借贷纠纷", "court_level": "基层人民法院", "year": "2022", "summary": "原告李某仅有转账凭证起诉被告还款。法院结合间接证据支持原告诉请。"}', '原告李某于2021年向被告周某银行转账30万元，无书面借款合同。周某主张该款系李某偿还之前的货款。李某诉至法院要求周某偿还借款。法院经审理查明，李某与周某此前无生意往来，周某无法提供货款往来的证据。转账后周某曾通过微信表示会尽快还款。法院认为，原告仅依据金融机构的转账凭证提起民间借贷诉讼，被告抗辩转账系偿还双方之前借款或其他债务的，被告应当对其主张提供证据证明。周某举证不足。判决周某偿还李某30万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某小额贷款公司诉吴某借款合同纠纷案', '某市中级人民法院', '{"cause": "借贷纠纷", "court_level": "中级人民法院", "year": "2023", "summary": "被告吴某向小贷公司借款后主张利息过高。法院调整利率至法定上限。"}', '被告吴某于2022年向原告某小贷公司借款20万元，合同约定年利率36%，服务费2万元。吴某偿还3期后停止还款。小贷公司起诉要求偿还本息。法院经审理查明，合同中约定的年利率36%及服务费折合实际年利率超过42%。法院认为，民间借贷的利率不得超过合同成立时一年期贷款市场报价利率的四倍。超过部分不受法律保护。判决吴某偿还本金及按法定上限利率计算的利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '郑某诉某投资公司借款合同纠纷案', '某省高级人民法院', '{"cause": "借贷纠纷", "court_level": "高级人民法院", "year": "2020", "summary": "原告郑某通过投资公司出借资金，公司承诺保本付息。法院认定名为投资实为借贷。"}', '原告郑某与被告某投资公司签订《投资理财协议》，投入100万元，约定年收益15%，公司承诺保本付息。到期后公司未返还本金和收益。法院经审理查明，协议约定固定收益且公司保本，郑某不承担投资风险，不符合投资特征。法院认为，合同约定一方提供资金，另一方承诺固定收益不承担风险的，应当认定为民间借贷关系。判决投资公司偿还郑某100万元及按法定利率计算的利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '陈某诉王某保证合同纠纷案', '某区基层人民法院', '{"cause": "借贷纠纷", "court_level": "基层人民法院", "year": "2021", "summary": "原告陈某为债务人提供担保，债务人跑路后债权人要求陈某承担保证责任。法院判决陈某承担连带责任。"}', '案外人林某向债权人借款50万元，由原告陈某提供连带责任保证。借款到期后林某失联，债权人要求陈某承担保证责任。陈某主张应先执行林某的财产。法院经审理查明，保证合同约定陈某承担连带保证责任。法院认为，连带责任保证的债务人在主合同规定的债务履行期届满没有履行债务的，债权人可以要求债务人履行债务，也可以要求保证人在其保证范围内承担保证责任。判决陈某偿还50万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某银行诉某公司票据追索权纠纷案', '某市中级人民法院', '{"cause": "借贷纠纷", "court_level": "中级人民法院", "year": "2024", "summary": "原告银行持承兑汇票要求出票人付款。法院判决支持票据追索权。"}', '原告某银行持有被告某公司签发的商业承兑汇票一张，金额100万元，到期后被告拒绝付款。银行诉至法院行使票据追索权。法院经审理查明，汇票真实有效，银行合法取得票据。法院认为，票据债务人应当按照票据记载的事项承担票据责任。判决被告支付银行100万元及利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '黄某诉某网贷平台借款纠纷案', '某区基层人民法院', '{"cause": "借贷纠纷", "court_level": "基层人民法院", "year": "2022", "summary": "原告黄某通过网贷平台借款，平台收取高额服务费。法院认定服务费应计入利息。"}', '原告黄某于2021年通过某网贷平台借款3万元，平台除收取年利率24%的利息外，还收取服务费4500元。黄某主张服务费变相提高利率。法院经审理查明，平台收取的服务费实质为利息的组成部分。法院认为，出借人与借款人约定了服务费等费用的，该费用应当计入利息。综合利息和服务费后的实际利率不得超过法定上限。判决超出法定上限部分的利息和服务费不予支持。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某资产管理公司诉某集团债权转让纠纷案', '某省高级人民法院', '{"cause": "借贷纠纷", "court_level": "高级人民法院", "year": "2023", "summary": "原告受让银行不良债权后向债务人追索。法院判决债务人偿还。"}', '原告某资产管理公司从银行受让了对被告某集团的债权2000万元，并通知了债务人。债务到期后某集团以债权转让未通知为由拒绝还款。法院经审理查明，债权转让已通过书面通知送达债务人。法院认为，债权人转让权利的，应当通知债务人。未经通知该转让对债务人不发生效力。本案债权转让已依法通知债务人。判决某集团偿还2000万元及利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '马某诉刘某民间借贷纠纷案', '某区基层人民法院', '{"cause": "借贷纠纷", "court_level": "基层人民法院", "year": "2019", "summary": "原告马某现金借款无转账记录。法院结合借条和证人证言认定借款事实。"}', '原告马某主张于2018年借给被告刘某现金10万元，有刘某出具的借条为证。刘某主张未收到款项。法院经审理查明，借条系刘某亲笔书写，且有在场证人证实马某交付了现金。法院认为，民间借贷中出借人以现金方式交付借款的，应当结合借条、证人证言等综合认定借款事实。判决刘某偿还马某10万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '高某诉某P2P平台债权确认纠纷案', '某市中级人民法院', '{"cause": "借贷纠纷", "court_level": "中级人民法院", "year": "2020", "summary": "原告高某通过P2P平台出借资金，平台爆雷后确认债权。法院确认原告对借款人的债权。"}', '原告高某通过P2P平台向多名借款人出借资金共计20万元。平台爆雷后高某要求确认对各借款人的债权。法院经审理查明，高某与各借款人的借贷合同真实有效。法院认为，P2P平台爆雷不影响出借人与借款人之间借贷合同的效力。判决确认高某对多名借款人的债权共计20万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某消费金融公司诉曾某消费贷纠纷案', '某区基层人民法院', '{"cause": "借贷纠纷", "court_level": "基层人民法院", "year": "2024", "summary": "被告曾某向消费金融公司借款后逾期。法院判决偿还本金及合法利息。"}', '被告曾某于2023年向原告某消费金融公司借款5万元用于装修，约定年利率28%，分24期偿还。曾某偿还6期后逾期。消费金融公司起诉要求一次性偿还剩余本息。法院经审理查明，约定的年利率28%超过法定上限。法院认为，消费贷款利率不得超过法定上限。判决曾某偿还剩余本金及按法定上限利率计算的利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '田某诉冯某借贷担保纠纷案', '某市中级人民法院', '{"cause": "借贷纠纷", "court_level": "中级人民法院", "year": "2021", "summary": "原告田某借款给冯某，担保人承担连带责任后追偿。法院判决支持追偿权。"}', '案外人何某向原告田某借款30万元，被告冯某提供连带保证担保。何某到期未还，田某直接要求冯某承担保证责任。冯某偿还后向何某追偿。法院经审理查明，冯某已代偿30万元。法院认为，保证人承担保证责任后有权向债务人追偿。判决何某偿还冯某30万元及资金占用费。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某银行诉许某房贷违约纠纷案', '某市中级人民法院', '{"cause": "借贷纠纷", "court_level": "中级人民法院", "year": "2022", "summary": "被告许某断供房贷，银行起诉要求提前还款。法院判决支持银行诉请。"}', '被告许某于2019年向原告某银行贷款200万元购房，约定30年分期还款。2021年起许某停止还款已逾期6期。银行宣布贷款提前到期，要求许某一次性偿还剩余本息180万元。法院经审理查明，许某连续逾期6期构成根本违约。法院认为，借款人未按约定还款的，贷款人有权按照约定提前收回贷款。判决许某偿还银行180万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '曹某诉某典当行典当纠纷案', '某区基层人民法院', '{"cause": "借贷纠纷", "court_level": "基层人民法院", "year": "2016", "summary": "原告曹某将珠宝典当给被告，赎回时被告索要高额费用。法院判决按约定标准收费。"}', '原告曹某于2015年将价值10万元的珠宝典当给被告某典当行，借款5万元，约定月综合费率4%。赎回时典当行要求支付综合费3.2万元。曹某认为费用过高。法院经审理查明，约定月费率4%折合年利率48%超过法定上限。法院认为，典当行收取的综合费实质为利息，应受民间借贷利率上限约束。判决超过法定上限部分的费用不予支持。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某食品公司诉某贸易公司商标侵权纠纷案', '某市中级人民法院', '{"cause": "知识产权", "court_level": "中级人民法院", "year": "2018", "summary": "被告销售假冒原告注册商标的商品。法院判决被告停止侵权并赔偿。"}', '原告某食品公司是某知名饮料品牌商标权人。2018年，原告发现被告某贸易公司销售假冒其注册商标的饮料。原告公证购买后诉至法院。法院经审理查明，被告销售的产品上使用的商标与原告注册商标完全相同，商品属同一类别。法院认为，销售侵犯注册商标专用权的商品的属于侵权行为。被告未能证明商品有合法来源。判决被告停止销售侵权产品并赔偿原告20万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某科技公司诉某电子公司专利侵权纠纷案', '某省高级人民法院', '{"cause": "知识产权", "court_level": "高级人民法院", "year": "2019", "summary": "被告生产的电子产品侵犯原告实用新型专利。法院判决被告停止制造并赔偿。"}', '原告某科技公司是某实用新型专利权人，专利涉及一种手机快充技术。原告发现被告某电子公司生产的充电器使用了其专利技术。法院经审理查明，经比对被告产品落入原告专利保护范围。法院认为，未经专利权人许可实施其专利的构成侵权。判决被告停止制造销售侵权产品并赔偿原告100万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某文化公司诉某网站著作权侵权纠纷案', '某市中级人民法院', '{"cause": "知识产权", "court_level": "中级人民法院", "year": "2020", "summary": "被告未经授权在网站传播原告影视作品。法院判决被告停止侵权并赔偿。"}', '原告某文化公司拥有某电视剧的信息网络传播权。被告某网站未经授权提供该剧在线播放服务。法院经审理查明，被告网站上确实提供了该剧的完整播放，且未获授权。法院认为，未经著作权人许可通过信息网络向公众传播其作品的构成侵权。判决被告停止侵权并赔偿原告15万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某餐饮公司诉某饭店不正当竞争纠纷案', '某市中级人民法院', '{"cause": "知识产权", "court_level": "中级人民法院", "year": "2021", "summary": "被告使用与原告近似的店名和装修风格。法院判决构成不正当竞争。"}', '原告某餐饮公司经营的连锁餐厅具有较高知名度，店名和装修风格具有显著特征。被告某饭店在附近开设同类型餐厅，使用近似的店名和相似的装修风格，导致消费者混淆。法院经审理查明，被告的使用行为足以使消费者误认。法院认为，经营者不得实施混淆行为引人误认为是他人商品或与他人存在特定联系。判决被告停止使用近似店名和装修并赔偿原告10万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某科技公司诉某员工商业秘密侵权纠纷案', '某省高级人民法院', '{"cause": "知识产权", "court_level": "高级人民法院", "year": "2022", "summary": "被告离职后使用原告商业秘密。法院判决被告停止使用并赔偿。"}', '原告某科技公司的前员工被告张某离职时带走原告的核心技术资料，入职竞争对手后使用该技术生产同类产品。法院经审理查明，张某带走的技术资料属于原告的商业秘密，已采取保密措施。法院认为，违反约定或权利人保密要求获取、使用商业秘密的构成侵权。判决张某停止使用原告商业秘密并赔偿50万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某服装公司诉某网店商标侵权纠纷案', '某区基层人民法院', '{"cause": "知识产权", "court_level": "基层人民法院", "year": "2021", "summary": "被告网店销售假冒原告品牌的服装。法院判决被告赔偿。"}', '原告某服装公司是某知名服装品牌商标权人。被告在某电商平台开设网店销售假冒该品牌的服装。法院经审理查明，被告销售的服装使用的商标与原告注册商标近似。法院认为，在同类商品上使用近似商标容易导致混淆的构成商标侵权。判决被告停止侵权并赔偿原告8万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某软件公司诉某企业软件著作权侵权纠纷案', '某市中级人民法院', '{"cause": "知识产权", "court_level": "中级人民法院", "year": "2020", "summary": "被告未经授权使用原告软件。法院判决被告停止使用并赔偿。"}', '原告某软件公司是某办公软件的著作权人。被告某企业未经购买授权在办公电脑上安装使用该软件共计200套。法院经审理查明，被告确实未经授权安装使用了原告软件。法院认为，未经软件著作权人许可安装使用其软件的构成侵权。判决被告停止使用并赔偿原告30万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某医药公司诉某药厂专利侵权纠纷案', '最高人民法院', '{"cause": "知识产权", "court_level": "最高人民法院", "year": "2023", "summary": "被告仿制原告专利药品。法院判决被告停止制造并赔偿。"}', '原告某医药公司是某药品发明专利权人。被告某药厂未经许可制造相同药品。法院经审理查明，被告药品的活性成分和生产工艺落入原告专利保护范围。法院认为，药品专利侵权应严格保护创新药企的合法权益。判决被告停止制造销售侵权药品并赔偿原告500万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某出版社诉某教育机构著作权侵权纠纷案', '某区基层人民法院', '{"cause": "知识产权", "court_level": "基层人民法院", "year": "2019", "summary": "被告未经授权使用原告出版的教材。法院判决被告赔偿。"}', '原告某出版社是某系列教材的著作权人。被告某教育机构在培训中大量复印该教材发给学生使用。法院经审理查明，被告复印教材未获授权且数量较大。法院认为，未经著作权人许可复制其作品的构成侵权。判决被告停止侵权并赔偿原告5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某化妆品公司诉某工厂商标侵权纠纷案', '某市中级人民法院', '{"cause": "知识产权", "court_level": "中级人民法院", "year": "2022", "summary": "被告为他人代工生产假冒原告品牌的化妆品。法院判决被告停止生产并赔偿。"}', '原告某化妆品公司是某知名品牌商标权人。被告某工厂接受他人委托代工生产假冒该品牌的化妆品。法院经审理查明，被告明知委托方未获授权仍为其代工生产。法院认为，代工生产者在明知或应知侵权的情况下仍生产的构成共同侵权。判决被告停止生产并赔偿原告30万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某游戏公司诉某公司游戏著作权侵权纠纷案', '某省高级人民法院', '{"cause": "知识产权", "court_level": "高级人民法院", "year": "2024", "summary": "被告开发的游戏抄袭原告游戏。法院判决被告停止运营并赔偿。"}', '原告某游戏公司开发的手游具有较高知名度。被告公司开发的同类游戏在人物形象、场景设计、玩法规则等方面大量抄袭原告游戏。法院经审理查明，被告游戏在美术素材、界面设计等方面与原告游戏实质性相似。法院认为，游戏中的美术作品、文字作品等受著作权法保护。判决被告停止运营侵权游戏并赔偿原告200万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某建材公司诉某公司外观设计专利侵权纠纷案', '某市中级人民法院', '{"cause": "知识产权", "court_level": "中级人民法院", "year": "2021", "summary": "被告生产的产品侵犯原告外观设计专利。法院判决被告停止生产并赔偿。"}', '原告某建材公司是某瓷砖外观设计专利权人。被告某公司生产外观相同的瓷砖。法院经审理查明，被告产品外观与原告专利设计实质性相似。法院认为，外观设计专利权被授予后任何单位或个人未经许可不得为生产经营目的制造其外观设计专利产品。判决被告停止生产并赔偿原告15万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某互联网公司诉某公司不正当竞争纠纷案', '某市中级人民法院', '{"cause": "知识产权", "court_level": "中级人民法院", "year": "2023", "summary": "被告通过技术手段抓取原告平台数据。法院判决构成不正当竞争。"}', '原告某互联网公司运营某社交平台，积累大量用户数据。被告某公司通过爬虫技术大量抓取原告平台用户公开数据，用于运营竞品平台。法院经审理查明，被告抓取数据规模巨大，导致原告服务器负载增加，且部分数据涉及用户隐私。法院认为，经营者不得通过技术手段获取他人商业数据构成不正当竞争。判决被告停止抓取行为并赔偿原告50万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某传媒公司诉某公众号著作权侵权纠纷案', '某区基层人民法院', '{"cause": "知识产权", "court_level": "基层人民法院", "year": "2022", "summary": "被告公众号未经授权转载原告文章。法院判决被告停止侵权并赔偿。"}', '原告某传媒公司拥有某原创文章的著作权。被告某公众号未经授权转载该文章并获得流量收益。法院经审理查明，被告转载行为未获授权且未标明出处。法院认为，未经著作权人许可转载其作品构成侵权。判决被告删除侵权文章并赔偿原告2万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某汽车公司诉某配件厂商标侵权纠纷案', '某省高级人民法院', '{"cause": "知识产权", "court_level": "高级人民法院", "year": "2024", "summary": "被告生产假冒原告品牌汽车配件。法院判决被告停止生产并赔偿。"}', '原告某汽车公司是某知名汽车品牌商标权人。被告某配件厂生产假冒该品牌的汽车配件并销售至多地。法院经审理查明，被告生产的配件使用的商标与原告注册商标相同，且产品质量低劣影响原告品牌声誉。法院认为，在汽车配件上使用他人注册商标构成商标侵权。判决被告停止生产销售并赔偿原告80万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某科技公司诉某员工发明专利权属纠纷案', '某市中级人民法院', '{"cause": "知识产权", "court_level": "中级人民法院", "year": "2020", "summary": "原告主张被告在职期间发明的专利应归公司所有。法院判决专利权归原告。"}', '原告某科技公司前员工被告王某在职期间发明了一项技术并申请了专利。原告主张该专利系职务发明，专利权应归公司所有。法院经审理查明，王某在原告公司担任研发工程师，该专利技术与王某在公司负责的研发项目密切相关，且利用了公司的技术资料和实验设备。法院认为，执行本单位的任务或者主要是利用本单位的物质技术条件所完成的发明创造为职务发明创造，专利权归单位。判决该专利权归原告所有。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某教育公司诉某公司域名纠纷案', '某区基层人民法院', '{"cause": "知识产权", "court_level": "基层人民法院", "year": "2025", "summary": "被告注册与原告商标近似的域名。法院判决被告注销域名。"}', '原告某教育公司拥有某知名教育品牌商标。被告注册了与原告商标高度近似的域名用于运营教育网站。法院经审理查明，被告域名与原告商标构成混淆性近似，且被告网站提供同类教育服务。法院认为，注册与他人注册商标近似的域名用于同类服务构成商标侵权。判决被告注销该域名并赔偿原告5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某音乐公司诉某KTV著作权侵权纠纷案', '某市中级人民法院', '{"cause": "知识产权", "court_level": "中级人民法院", "year": "2018", "summary": "被告KTV未经授权使用原告音乐作品。法院判决被告停止侵权并赔偿。"}', '原告某音乐公司拥有多首流行歌曲的著作权。被告某KTV未经授权在其经营场所的点歌系统中使用原告音乐作品。法院经审理查明，被告点歌系统中收录了原告拥有著作权的歌曲200余首。法院认为，未经著作权人许可在经营场所播放其作品构成侵权。判决被告停止侵权并赔偿原告10万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '张某诉某公司股权转让纠纷案', '某市中级人民法院', '{"cause": "公司股权", "court_level": "中级人民法院", "year": "2017", "summary": "原告张某将股权转让给被告，被告拒付转让款。法院判决被告支付转让款及违约金。"}', '原告张某系某公司股东，持有20%股权。2016年张某与被告李某签订《股权转让协议》，约定张某将其持有的全部股权以200万元转让给李某。协议签订后张某配合办理了股权变更登记，但李某仅支付100万元后拒付余款。法院经审理查明，股权转让协议合法有效，张某已履行股权变更义务。法院认为，股权转让合同当事人应当按照约定履行义务。判决李某支付余款100万元及违约金。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某股东诉某公司股东出资纠纷案', '某区基层人民法院', '{"cause": "公司股权", "court_level": "基层人民法院", "year": "2019", "summary": "原告起诉被告未按章程缴纳出资。法院判决被告补缴出资款。"}', '原告与被告共同设立某公司，注册资本500万元，被告认缴200万元。公司章程约定出资期限为2018年12月。至2019年被告仍有100万元未缴。公司诉至法院要求被告补缴。法院经审理查明，被告确实未按章程约定的期限缴纳出资。法院认为，股东应当按期足额缴纳公司章程中规定的各自所认缴的出资额。判决被告补缴出资100万元及利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某股东诉某公司决议撤销纠纷案', '某市中级人民法院', '{"cause": "公司股权", "court_level": "中级人民法院", "year": "2020", "summary": "原告股东主张公司决议程序违法要求撤销。法院判决撤销该决议。"}', '原告系某公司股东，持有15%股权。2020年3月公司召开股东会作出增资决议，但未按章程规定提前15日通知原告。原告未出席会议，诉至法院要求撤销该决议。法院经审理查明，公司召开股东会未按章程规定提前通知全体股东。法院认为，股东会会议召集程序违反公司章程的，股东可以请求撤销。判决撤销该增资决议。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某股东诉某公司知情权纠纷案', '某区基层人民法院', '{"cause": "公司股权", "court_level": "基层人民法院", "year": "2021", "summary": "原告股东要求查阅公司财务账簿被拒。法院判决公司提供查阅。"}', '原告系某公司股东，持有10%股权。原告向公司提出查阅公司会计账簿和财务报告的书面请求，公司以原告可能泄露商业秘密为由拒绝。法院经审理查明，原告已提出书面请求并说明目的，公司未提供证据证明原告有不正当目的。法院认为，股东有权查阅复制公司章程、股东会会议记录和财务会计报告，也可以要求查阅公司会计账簿。判决公司在15日内提供相关材料供原告查阅。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某股东诉某公司解散清算纠纷案', '某省高级人民法院', '{"cause": "公司股权", "court_level": "高级人民法院", "year": "2022", "summary": "原告股东主张公司经营管理困难请求解散。法院判决解散公司。"}', '原告系某公司股东，持有40%股权。公司自2019年起股东会无法召开，公司经营陷入瘫痪，连续三年亏损。原告诉至法院请求解散公司。法院经审理查明，公司股东之间矛盾激化，持续两年无法召开股东会，公司经营管理发生严重困难，继续存续会使股东利益受到重大损失。法院认为，公司经营管理发生严重困难，继续存续会使股东利益受到重大损失，通过其他途径不能解决的，持有公司全部股东表决权百分之十以上的股东可以请求人民法院解散公司。判决解散公司。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '赵某诉某公司股权确认纠纷案', '某市中级人民法院', '{"cause": "公司股权", "court_level": "中级人民法院", "year": "2018", "summary": "原告主张其系隐名股东要求确认股权。法院判决确认其股东资格。"}', '原告赵某与被告某公司登记股东钱某签订代持协议，由赵某出资100万元购买公司10%股权，登记在钱某名下。后双方发生争议，赵某诉至法院要求确认股东资格。法院经审理查明，赵某实际出资100万元，且参与了公司分红和经营决策，其他股东知晓并认可赵某的股东身份。法院认为，实际出资人与名义出资人订立合同约定由实际出资人出资并享有投资权益，如无合同法规定的无效情形，应当认定合同有效。判决确认赵某的股东资格。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某公司诉某股东抽逃出资纠纷案', '某区基层人民法院', '{"cause": "公司股权", "court_level": "基层人民法院", "year": "2019", "summary": "被告股东在公司成立后抽逃出资。法院判决被告返还出资款。"}', '被告孙某系某公司股东，认缴出资200万元。公司成立后，孙某通过虚构交易将180万元转出至其个人账户。公司诉至法院要求孙某返还。法院经审理查明，孙某通过虚构交易方式将出资款转出，属于抽逃出资。法院认为，股东不得抽逃出资。抽逃出资的股东应当向公司返还出资本息。判决孙某返还公司180万元及利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某股东诉某公司利润分配纠纷案', '某市中级人民法院', '{"cause": "公司股权", "court_level": "中级人民法院", "year": "2023", "summary": "原告股东要求公司分配利润被拒。法院判决公司分配利润。"}', '原告系某公司股东，持有20%股权。公司2022年度净利润500万元，但公司以需要留存资金发展为由拒绝分配利润。原告诉至法院要求分配利润。法院经审理查明，公司连续三年盈利但从未分配利润，且公司章程约定每年应按净利润的30%分配。法院认为，公司连续五年不向股东分配利润而公司该五年连续盈利的，对股东会该项决议投反对票的股东可以请求公司按照合理的价格收购其股权。但公司章程另有约定的从其约定。判决公司按章程约定分配利润100万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某投资公司诉某集团股权转让纠纷案', '某省高级人民法院', '{"cause": "公司股权", "court_level": "高级人民法院", "year": "2021", "summary": "原告受让股权后发现目标公司存在未披露债务。法院判决撤销股权转让合同。"}', '原告某投资公司与被告某集团签订《股权转让协议》，以3000万元受让某公司100%股权。协议约定被告保证目标公司无未披露债务。交易完成后原告发现目标公司有未披露债务800万元。法院经审理查明，被告在签约时明知目标公司存在800万元未披露债务但未告知原告。法院认为，股权转让方隐瞒目标公司债务构成欺诈，受让方有权请求撤销合同。判决撤销股权转让协议，被告返还转让款并赔偿损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '王某诉某公司股东资格确认纠纷案', '某市中级人民法院', '{"cause": "公司股权", "court_level": "中级人民法院", "year": "2020", "summary": "原告主张其通过增资成为公司股东。法院判决确认股东资格。"}', '原告王某与某公司及其他股东签订增资协议，约定王某向公司投资500万元取得20%股权。王某按约交付投资款后，公司未办理股东变更登记。王某诉至法院要求确认股东资格。法院经审理查明，王某已实际缴纳出资款，公司其他股东过半数同意王某入股。法院认为，投资人已实际出资并经其他股东过半数同意的，应当确认其股东资格。判决确认王某的股东资格，公司应办理变更登记。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某股东诉某公司优先购买权纠纷案', '某市中级人民法院', '{"cause": "公司股权", "court_level": "中级人民法院", "year": "2019", "summary": "原告股东主张公司转让股权时侵犯其优先购买权。法院判决转让行为对原告无效。"}', '原告系某公司股东，持有30%股权。被告公司另一股东将其股权转让给公司外第三人，未通知原告也未给予原告优先购买的机会。原告诉至法院主张优先购买权。法院经审理查明，转让方未按照法律规定提前通知其他股东。法院认为，股东向股东以外的人转让股权应当经其他股东过半数同意，其他股东在同等条件下有优先购买权。判决该股权转让对原告不生效，原告有权在同等条件下购买该股权。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某公司诉某高管损害公司利益责任纠纷案', '某省高级人民法院', '{"cause": "公司股权", "court_level": "高级人民法院", "year": "2024", "summary": "被告高管利用职务便利将公司业务转移至关联公司。法院判决被告赔偿公司损失。"}', '被告系某公司总经理，在职期间设立关联公司，将原告公司的核心客户和业务逐步转移至关联公司，致原告公司利润大幅下降。法院经审理查明，被告作为公司高管违反忠实义务，将公司商业机会转移至关联公司。法院认为，董事监事高级管理人员应当遵守法律和公司章程，对公司负有忠实义务和勤勉义务，不得利用职权牟取不当利益。判决被告赔偿公司损失200万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '刘某诉某公司股东会决议效力纠纷案', '某区基层人民法院', '{"cause": "公司股权", "court_level": "基层人民法院", "year": "2022", "summary": "原告主张股东会决议内容违法要求确认无效。法院判决决议无效。"}', '原告系某公司股东。公司召开股东会通过决议，将原告的股权强制转让给另一股东。原告未参加该次会议，诉至法院主张决议无效。法院经审理查明，该决议在原告未出席的情况下强制转让其股权。法院认为，股东会决议内容违反法律行政法规的无效。公司无权强制转让股东股权。判决该股东会决议无效。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某科技公司诉某投资方对赌协议纠纷案', '某市中级人民法院', '{"cause": "公司股权", "court_level": "中级人民法院", "year": "2023", "summary": "投资方要求创始股东按对赌协议回购股权。法院判决支持投资方回购请求。"}', '原告某投资方与被告某科技公司创始股东签订对赌协议，约定若公司未在2022年底前完成IPO，投资方有权要求创始股东以年化10%的回报率回购股权。公司未能如期上市，投资方要求回购。法院经审理查明，对赌协议系双方真实意思表示，不违反法律强制性规定。法院认为，投资方与股东之间的对赌协议有效，股东应当按约履行回购义务。判决创始股东回购投资方股权并支付约定回报。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某股东诉某公司公司减资纠纷案', '某市中级人民法院', '{"cause": "公司股权", "court_level": "中级人民法院", "year": "2021", "summary": "公司减资未通知债权人致股东承担补充责任。法院判决股东在减资范围内承担责任。"}', '某公司注册资本1000万元，2020年减资至500万元，但未依法通知债权人。债权人债权无法实现后起诉股东要求在减资范围内承担补充责任。法院经审理查明，公司减资未按法定程序通知债权人。法院认为，公司减资应当通知债权人，未依法通知债权人的减资不得对抗债权人。股东在减资范围内对公司债务承担补充赔偿责任。判决股东在减资500万元范围内对债权人承担补充责任。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '陈某诉某公司发起人责任纠纷案', '某区基层人民法院', '{"cause": "公司股权", "court_level": "基层人民法院", "year": "2018", "summary": "公司设立失败发起人之间对费用承担产生争议。法院判决各发起人按比例分担。"}', '原告陈某与被告等人共同发起设立某公司，原告垫付设立费用30万元。后公司因故未能成立，各发起人对费用承担产生争议。法院经审理查明，公司未能成立系市场环境变化所致，各发起人无过错。法院认为，公司不能成立时，发起人对设立行为所产生的费用和债务负连带责任。各发起人应按约定的出资比例分担。判决各发起人按比例分担30万元设立费用。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某股东诉某公司清算责任纠纷案', '某省高级人民法院', '{"cause": "公司股权", "court_level": "高级人民法院", "year": "2025", "summary": "公司清算组未依法通知债权人致债权人损失。法院判决清算组成员承担赔偿责任。"}', '某公司进行清算注销，清算组未依法通知已知债权人某供应商，致供应商80万元债权无法申报受偿。供应商起诉清算组成员要求赔偿。法院经审理查明，清算组明知供应商的债权但未书面通知。法院认为，清算组应当自成立之日起十日内通知已知债权人。清算组未履行通知义务致债权人损失的，应当承担赔偿责任。判决清算组成员赔偿供应商80万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某股东诉某公司高管薪酬纠纷案', '某区基层人民法院', '{"cause": "公司股权", "court_level": "基层人民法院", "year": "2020", "summary": "股东主张高管薪酬过高未经股东会批准。法院判决调整高管薪酬。"}', '原告系某公司持股20%的股东。公司董事长自行决定将年薪从50万元提高至200万元，未经股东会批准。原告诉至法院要求确认薪酬调整无效。法院经审理查明，公司章程规定高管薪酬应由股东会决定。法院认为，董事高管薪酬应当依照公司章程规定由股东会决定。未经股东会批准的薪酬调整对超出合理范围部分不予支持。判决董事长退还超出原薪酬部分。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '张某盗窃罪辩护案', '某区基层人民法院', '{"cause": "刑事辩护", "court_level": "基层人民法院", "year": "2017", "summary": "被告人张某因盗窃被起诉。法院认定盗窃罪名成立但考虑自首情节从轻处罚。"}', '被告人张某于2017年3月在某商场盗窃他人手机一部，价值5000元。案发后张某主动投案并如实供述犯罪事实。法院经审理查明，张某盗窃事实清楚，证据充分，构成盗窃罪。但张某有自首情节且系初犯，认罪悔罪态度好。法院认为，盗窃公私财物数额较大的处三年以下有期徒刑拘役或管制。张某有自首情节依法可以从轻或减轻处罚。判决张某犯盗窃罪判处拘役三个月并处罚金5000元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '李某诈骗罪辩护案', '某市中级人民法院', '{"cause": "刑事辩护", "court_level": "中级人民法院", "year": "2019", "summary": "被告人李某以投资为名骗取他人钱财。法院认定诈骗罪成立。"}', '被告人李某虚构投资项目，以高额回报为诱饵骗取被害人王某等10人投资款共计150万元，所得款项用于个人挥霍。法院经审理查明，李某以非法占有为目的虚构事实骗取他人财物，数额特别巨大，构成诈骗罪。法院认为，诈骗公私财物数额特别巨大的处十年以上有期徒刑或无期徒刑并处罚金或没收财产。判决李某犯诈骗罪判处有期徒刑十二年并处罚金20万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '王某故意伤害罪辩护案', '某区基层人民法院', '{"cause": "刑事辩护", "court_level": "基层人民法院", "year": "2018", "summary": "被告人王某因纠纷打伤他人。法院考虑被害人过错从轻处罚。"}', '被告人王某与被害人赵某因停车纠纷发生争执，王某将赵某打致轻伤二级。案发后王某赔偿赵某并取得谅解。法院经审理查明，王某故意伤害他人身体致轻伤，构成故意伤害罪。但被害人赵某在纠纷中有过错，且王某已积极赔偿取得谅解。法院认为，故意伤害他人身体的处三年以下有期徒刑拘役或管制。鉴于被害人有过错且被告人已赔偿谅解，从轻处罚。判决王某有期徒刑六个月缓刑一年。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '陈某危险驾驶罪辩护案', '某区基层人民法院', '{"cause": "刑事辩护", "court_level": "基层人民法院", "year": "2020", "summary": "被告人陈某醉酒驾驶被查获。法院认定危险驾驶罪成立。"}', '被告人陈某于2020年5月饮酒后驾驶轿车，血液酒精含量为120mg/100ml，被交警查获。法院经审理查明，陈某醉酒后在道路上驾驶机动车，构成危险驾驶罪。陈某到案后如实供述且系初犯。法院认为，在道路上醉酒驾驶机动车的处拘役并处罚金。判决陈某犯危险驾驶罪判处拘役二个月并处罚金5000元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某企业非法经营罪辩护案', '某市中级人民法院', '{"cause": "刑事辩护", "court_level": "中级人民法院", "year": "2021", "summary": "被告企业未经许可经营专营业务。法院认定非法经营罪成立。"}', '被告某企业在未取得烟草专卖许可证的情况下大量购销卷烟，经营额达200万元。法院经审理查明，被告企业违反国家规定未经许可经营法律行政法规规定的专营专卖物品，情节严重，构成非法经营罪。法院认为，违反国家规定未经许可经营专营专卖物品扰乱市场秩序情节严重的处五年以下有期徒刑或拘役并处罚金。判决被告企业罚金50万元，直接责任人有期徒刑三年并处罚金10万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '赵某职务侵占罪辩护案', '某市中级人民法院', '{"cause": "刑事辩护", "court_level": "中级人民法院", "year": "2022", "summary": "被告人赵某利用职务便利侵占公司资金。法院认定职务侵占罪成立。"}', '被告人赵某系某公司财务主管，利用职务便利将公司资金80万元转入个人账户用于投资。法院经审理查明，赵某利用职务便利将本单位财物非法占为己有，数额较大，构成职务侵占罪。赵某到案后退赔全部赃款。法院认为，公司企业人员利用职务便利将本单位财物非法占为己有数额较大的处三年以下有期徒刑或拘役并处罚金。判决赵某有期徒刑二年缓刑三年并处罚金5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '刘某盗窃罪辩护案', '某区基层人民法院', '{"cause": "刑事辩护", "court_level": "基层人民法院", "year": "2019", "summary": "被告人刘某入户盗窃被当场抓获。法院从重处罚。"}', '被告人刘某于2019年7月撬门进入某居民住宅盗窃现金和首饰共计价值3万元，被回家的房主当场抓获。法院经审理查明，刘某入户盗窃他人财物数额较大，构成盗窃罪。入户盗窃属于从重处罚情节。法院认为，盗窃公私财物数额较大的处三年以下有期徒刑拘役或管制。入户盗窃应从重处罚。判决刘某有期徒刑一年六个月并处罚金1万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '孙某交通肇事罪辩护案', '某市中级人民法院', '{"cause": "刑事辩护", "court_level": "中级人民法院", "year": "2020", "summary": "被告人孙某醉驾致一人死亡。法院认定交通肇事罪成立。"}', '被告人孙某于2020年3月醉酒后驾驶车辆，在转弯处与对面正常行驶的摩托车相撞，致摩托车驾驶员当场死亡。交警认定孙某负事故全部责任。法院经审理查明，孙某违反道路交通安全法规醉酒驾驶致一人死亡，构成交通肇事罪。孙某案发后主动报警并在现场等待。法院认为，交通肇事致人死亡的处三年以下有期徒刑或拘役。孙某有自首情节且积极赔偿被害人家属取得谅解。判决孙某有期徒刑一年六个月。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '周某诈骗罪辩护案', '某市中级人民法院', '{"cause": "刑事辩护", "court_level": "中级人民法院", "year": "2021", "summary": "被告人周某网络诈骗。法院考虑退赃从轻处罚。"}', '被告人周某通过社交软件冒充公检法人员，骗取被害人转账共计30万元。案发后周某家属退赔全部赃款。法院经审理查明，周某以非法占有为目的虚构事实骗取他人财物数额巨大构成诈骗罪。法院认为，诈骗数额巨大的处三年以上十年以下有期徒刑。周某家属代为退赔全部赃款可从轻处罚。判决周某有期徒刑四年并处罚金5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '吴某毒品犯罪辩护案', '某省高级人民法院', '{"cause": "刑事辩护", "court_level": "高级人民法院", "year": "2022", "summary": "被告人吴某贩卖毒品被当场抓获。法院从严处罚。"}', '被告人吴某于2022年1月向他人贩卖甲基苯丙胺50克，交易时被公安机关当场抓获。法院经审理查明，吴某贩卖甲基苯丙胺50克，构成贩卖毒品罪。法院认为，贩卖甲基苯丙胺五十克以上的处十五年有期徒刑无期徒刑或死刑并处没收财产。判决吴某无期徒刑并处没收个人财产。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '郑某敲诈勒索罪辩护案', '某区基层人民法院', '{"cause": "刑事辩护", "court_level": "基层人民法院", "year": "2023", "summary": "被告人郑某以曝光隐私为由敲诈勒索。法院认定敲诈勒索罪成立。"}', '被告人郑某获取了被害人陈某的私密照片，以公开照片为由威胁陈某支付20万元。陈某报警后郑某被抓获。法院经审理查明，郑某以威胁手段敲诈勒索他人财物数额巨大构成敲诈勒索罪。法院认为，敲诈勒索公私财物数额巨大的处三年以上十年以下有期徒刑并处罚金。判决郑某有期徒刑五年并处罚金3万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '黄某寻衅滋事罪辩护案', '某区基层人民法院', '{"cause": "刑事辩护", "court_level": "基层人民法院", "year": "2019", "summary": "被告人黄某酒后闹事打砸店铺。法院认定寻衅滋事罪成立。"}', '被告人黄某于2019年6月醉酒后在某商业街随意殴打路人并打砸沿街店铺，造成财产损失1.5万元。法院经审理查明，黄某在公共场所随意殴打他人损毁公私财物情节恶劣构成寻衅滋事罪。法院认为，寻衅滋事情节恶劣的处五年以下有期徒刑拘役或管制。判决黄某有期徒刑一年并处罚金5000元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '冯某合同诈骗罪辩护案', '某市中级人民法院', '{"cause": "刑事辩护", "court_level": "中级人民法院", "year": "2024", "summary": "被告人冯某签订合同后骗取货款逃匿。法院认定合同诈骗罪成立。"}', '被告人冯某以虚假公司名义与被害单位签订采购合同，收取预付款100万元后逃匿。法院经审理查明，冯某以非法占有为目的在签订履行合同过程中骗取对方当事人财物数额巨大构成合同诈骗罪。法院认为，合同诈骗数额巨大的处三年以上十年以下有期徒刑并处罚金。判决冯某有期徒刑七年并处罚金10万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '许某故意伤害致人死亡罪辩护案', '某省高级人民法院', '{"cause": "刑事辩护", "court_level": "高级人民法院", "year": "2020", "summary": "被告人许某持刀伤人致死。法院考虑被害人过错从轻处罚。"}', '被告人许某与被害人因琐事发生冲突，被害人先动手殴打许某，许某持刀将被害人刺伤，被害人经抢救无效死亡。法院经审理查明，许某故意伤害他人身体致人死亡构成故意伤害罪。但被害人先动手有过错，许某有自首情节。法院认为，故意伤害致人死亡的处十年以上有期徒刑无期徒刑或死刑。鉴于被害人有过错且被告人自首从轻处罚。判决许某有期徒刑十年。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '何某贪污罪辩护案', '某省高级人民法院', '{"cause": "刑事辩护", "court_level": "高级人民法院", "year": "2023", "summary": "被告人何某利用职务便利贪污公款。法院认定贪污罪成立。"}', '被告人何某系某国企财务部经理，利用职务便利通过虚开发票等方式将公款120万元据为己有。法院经审理查明，何某利用职务便利侵吞公共财物数额巨大构成贪污罪。法院认为，贪污数额巨大的处三年以上十年以下有期徒刑并处罚金或没收财产。何某到案后退赔全部赃款并如实供述。判决何某有期徒刑六年并处罚金20万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '张某诉某区市场监管局行政处罚纠纷案', '某区基层人民法院', '{"cause": "行政诉讼", "court_level": "基层人民法院", "year": "2019", "summary": "原告张某被市场监管局罚款。法院认为处罚过重判决变更。"}', '原告张某经营一小餐馆，因食品安全检查中被发现使用过期食材，被告某区市场监管局对其罚款5万元并吊销许可证。张某认为处罚过重诉至法院。法院经审理查明，张某使用过期食材情节轻微且未造成实际危害，系初犯。法院认为，行政处罚应当与违法行为的事实性质情节及社会危害程度相当。罚款5万元并无不当但吊销许可证处罚过重。判决变更处罚为罚款5万元不吊销许可证。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某公司诉某市环保局行政处罚纠纷案', '某市中级人民法院', '{"cause": "行政诉讼", "court_level": "中级人民法院", "year": "2020", "summary": "原告公司被环保局处罚。法院认定处罚程序违法判决撤销。"}', '原告某公司因废水排放超标被被告某市环保局处以罚款30万元。原告主张环保局在作出处罚前未告知其享有听证权利。法院经审理查明，环保局在作出较大数额罚款前确实未告知原告听证权利，程序违法。法院认为，行政机关作出较大数额罚款等行政处罚前应当告知当事人有要求举行听证的权利。判决撤销该行政处罚决定。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '王某诉某市公安局行政强制纠纷案', '某区基层人民法院', '{"cause": "行政诉讼", "court_level": "基层人民法院", "year": "2021", "summary": "原告王某被公安拘留。法院认定行政强制措施违法。"}', '原告王某因与他人纠纷被某市公安局处以行政拘留15日。王某主张其行为不构成违法处罚。法院经审理查明，王某的行为系民事纠纷中的正常争执，不构成违反治安管理行为。法院认为，公安机关对不构成违反治安管理行为的人采取行政拘留没有法律依据。判决确认行政拘留决定违法并赔偿王某损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某企业诉某区规划局行政许可纠纷案', '某市中级人民法院', '{"cause": "行政诉讼", "court_level": "中级人民法院", "year": "2018", "summary": "原告企业申请施工许可被拒。法院判决规划局重新作出决定。"}', '原告某企业向被告某区规划局申请施工许可证，规划局以材料不全为由拒绝。企业补充材料后再次申请仍被拒。法院经审理查明，原告提交的材料已符合法定要求，规划局未明确指出缺少何种材料。法院认为，行政机关对符合条件的行政许可申请应当依法准予许可。判决撤销拒绝决定，责令规划局重新作出行政许可决定。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '赵某诉某市政府信息公开纠纷案', '某市中级人民法院', '{"cause": "行政诉讼", "court_level": "中级人民法院", "year": "2022", "summary": "原告赵某申请政府信息公开被拒。法院判决公开相关信息。"}', '原告赵某向被告某市政府申请公开某征地项目的补偿方案，市政府以涉及商业秘密为由拒绝。法院经审理查明，征地补偿方案属于应当公开的政府信息，不涉及商业秘密。法院认为，行政机关应当依法公开涉及公民法人或其他组织切身利益的政府信息。判决市政府在15日内向赵某公开相关信息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某公司诉某区税务局行政复议纠纷案', '某省高级人民法院', '{"cause": "行政诉讼", "court_level": "高级人民法院", "year": "2023", "summary": "原告公司不服税务局处罚经复议后起诉。法院维持复议决定。"}', '原告某公司因虚开发票被某区税务局处以罚款50万元。公司向市税务局申请行政复议，复议维持原处罚。公司不服诉至法院。法院经审理查明，公司虚开发票事实清楚，税务局处罚程序合法、幅度适当。法院认为，复议机关维持原行政行为的，作出原行政行为的机关和复议机关为共同被告。原处罚决定认定事实清楚适用法律正确。判决维持原处罚决定。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '李某诉某区城管局行政强制拆除纠纷案', '某区基层人民法院', '{"cause": "行政诉讼", "court_level": "基层人民法院", "year": "2021", "summary": "原告李某房屋被城管强拆。法院认定强制拆除程序违法。"}', '原告李某的房屋被某区城管局认定为违建并强制拆除。李某主张城管局未下达书面拆除决定也未给予复议诉讼期限。法院经审理查明，城管局未依法作出书面拆除决定即直接拆除房屋，程序违法。法院认为，行政机关实施行政强制拆除应当依法作出书面决定并告知当事人救济权利。判决确认强制拆除行为违法。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某商户诉某区市场监管局行政处罚纠纷案', '某市中级人民法院', '{"cause": "行政诉讼", "court_level": "中级人民法院", "year": "2024", "summary": "原告商户因虚假宣传被处罚。法院认为处罚适当判决维持。"}', '原告某商户在广告中虚构产品功效被被告某区市场监管局处以罚款20万元。商户认为罚款过高。法院经审理查明，商户虚假宣传行为情节严重，影响消费者权益。法院认为，行政处罚与违法行为相当。罚款20万元符合法律规定。判决维持行政处罚决定。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某村民诉某县政府征地补偿纠纷案', '某市中级人民法院', '{"cause": "行政诉讼", "court_level": "中级人民法院", "year": "2017", "summary": "原告村民不服县政府征地补偿标准。法院判决提高补偿标准。"}', '原告某村村民承包的土地被被告某县政府征收用于建设工业园区，县政府按每亩3万元补偿。原告认为补偿标准过低。法院经审理查明，该地区类似土地市场价约每亩8万元，补偿标准明显偏低。法院认为，征收土地应当依法给予公平合理的补偿，保障被征地农民生活水平不降低。判决县政府按每亩6万元标准补偿。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '陈某诉某市交警支队行政处罚纠纷案', '某区基层人民法院', '{"cause": "行政诉讼", "court_level": "基层人民法院", "year": "2020", "summary": "原告陈某被交警处罚。法院认定处罚证据不足判决撤销。"}', '原告陈某被某市交警支队以闯红灯为由处以罚款200元并扣6分。陈某主张其未闯红灯。法院经审理查明，交警部门仅有一张模糊照片，无法清晰辨认车辆是否闯红灯。法院认为，行政处罚应当事实清楚证据确凿。现有证据不足以证明陈某闯红灯。判决撤销该行政处罚。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某企业诉某区消防大队行政许可纠纷案', '某区基层人民法院', '{"cause": "行政诉讼", "court_level": "基层人民法院", "year": "2022", "summary": "原告企业消防许可申请被拒。法院判决消防大队重新审查。"}', '原告某企业向被告某区消防大队申请消防安全检查合格证，消防大队以消防通道不达标为由拒绝。企业按要求整改后再次申请仍被拒。法院经审理查明，企业已按消防规范完成整改，消防大队未提供不达标的具体依据。法院认为，行政机关对符合条件的许可申请应当准予。判决撤销拒绝决定，责令消防大队重新审查。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '刘某诉某区人社局工伤认定纠纷案', '某市中级人民法院', '{"cause": "行政诉讼", "court_level": "中级人民法院", "year": "2023", "summary": "原告刘某因工伤认定被撤销起诉。法院判决恢复工伤认定。"}', '原告刘某在工作中受伤后被某区人社局认定为工伤。后用人单位申请复议，人社局以劳动关系不明确为由撤销工伤认定。刘某诉至法院。法院经审理查明，刘某与用人单位存在事实劳动关系，人社局撤销工伤认定缺乏依据。法院认为，行政机关撤销已作出的行政行为应当有充分依据。判决撤销人社局的撤销决定，恢复工伤认定。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某公司诉某海关行政处罚纠纷案', '某省高级人民法院', '{"cause": "行政诉讼", "court_level": "高级人民法院", "year": "2025", "summary": "原告公司因报关错误被海关处罚。法院认定原告有过错但处罚适当。"}', '原告某公司在进口货物时因报关单填写错误被被告某海关处以罚款30万元。公司主张系代理报关行失误。法院经审理查明，报关错误系代理报关行操作失误所致，但公司作为委托方未尽到审核义务。法院认为，委托人对代理人的行为承担法律责任。但海关处罚时应考虑过错程度。判决维持罚款但适当调整。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某银行诉某公司执行异议纠纷案', '某市中级人民法院', '{"cause": "执行案件", "court_level": "中级人民法院", "year": "2019", "summary": "案外人对执行标的提出异议。法院驳回异议。"}', '原告某银行申请执行被告某公司财产。案外人赵某主张被执行的设备系其所有，提出执行异议。法院经审理查明，设备购销合同虽以赵某名义签订，但实际付款人和使用人均为被执行公司。法院认为，案外人对执行标的主张所有权的，应当提供充分证据。赵某的证据不足以证明其所有权。判决驳回执行异议。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某债权人诉某债务人执行异议之诉案', '某市中级人民法院', '{"cause": "执行案件", "court_level": "中级人民法院", "year": "2020", "summary": "案外人主张被执行房产系其所有。法院支持异议。"}', '债权人申请执行债务人名下房产。案外人钱某主张该房产系其借债务人名义购买，实际归其所有。法院经审理查明，购房款由钱某支付，房产由钱某实际居住使用，双方有代持协议。法院认为，案外人有充分证据证明其为实际权利人的，其异议成立。判决不得执行该房产。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某申请执行人诉被执行人执行回转纠纷案', '某区基层人民法院', '{"cause": "执行案件", "court_level": "基层人民法院", "year": "2021", "summary": "被执行人申请执行回转。法院支持回转请求。"}', '原执行案件将被执行人孙某的车辆拍卖执行。后再审改判孙某不承担债务。孙某申请执行回转。法院经审理查明，原判决已被再审改判，执行依据已消失。法院认为，据以执行的判决被撤销的，执行法院应当执行回转。判决申请执行人返还拍卖款及利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某债权人诉多债务人参与分配纠纷案', '某市中级人民法院', '{"cause": "执行案件", "court_level": "中级人民法院", "year": "2022", "summary": "多名债权人对被执行人财产申请参与分配。法院依法分配。"}', '被执行人某公司财产不足以清偿全部债务，多名债权人申请参与分配。法院经审理查明，被执行人财产总计500万元，债权总额2000万元，其中抵押债权800万元、普通债权1200万元。法院认为，参与分配中优先债权先予清偿，普通债权按比例分配。判决抵押债权全额受偿，普通债权按约35%比例分配。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '案外人孙某诉某银行执行异议之诉案', '某省高级人民法院', '{"cause": "执行案件", "court_level": "高级人民法院", "year": "2023", "summary": "案外人主张被执行账户资金系其所有。法院驳回异议。"}', '某银行申请执行某公司账户资金。案外人孙某主张该账户资金系其委托公司代收的货款。法院经审理查明，资金进入公司账户后已与公司其他资金混同，无法区分。法院认为，货币属于种类物，占有即所有。资金进入公司账户后即归公司所有，案外人仅享有债权请求权。判决驳回孙某的执行异议。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某申请执行人追加被执行人纠纷案', '某市中级人民法院', '{"cause": "执行案件", "court_level": "中级人民法院", "year": "2024", "summary": "申请执行人请求追加股东为被执行人。法院支持追加。"}', '被执行人某公司财产不足以清偿债务。申请执行人发现股东王某未实际缴纳出资，请求追加王某为被执行人。法院经审理查明，王某认缴出资200万元但实际未缴纳，公司财产不足以清偿债务。法院认为，被执行人财产不足以清偿生效法律文书确定的债务，股东未依法缴纳出资的，可以在未缴纳出资范围内追加为被执行人。判决追加王某为被执行人。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '周某诉某公司执行追加股东纠纷案', '某区基层人民法院', '{"cause": "执行案件", "court_level": "基层人民法院", "year": "2018", "summary": "申请执行人请求追加一人公司股东为被执行人。法院支持追加。"}', '被执行人系一人有限公司，财产不足以清偿债务。申请执行人请求追加股东周某为被执行人。法院经审理查明，该公司财产与股东个人财产混同，股东未能证明公司财产独立于个人财产。法院认为，一人有限责任公司的股东不能证明公司财产独立于股东自己财产的，应当对公司债务承担连带责任。判决追加股东为被执行人。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某银行诉某公司查封异议纠纷案', '某市中级人民法院', '{"cause": "执行案件", "court_level": "中级人民法院", "year": "2020", "summary": "案外人主张查封房产系其所有。法院驳回异议。"}', '某银行申请查封被执行人名下房产。案外人主张该房产已售予案外人但未过户。法院经审理查明，案外人与被执行人签订买卖合同但未办理过户登记，案外人未实际占有使用房产。法院认为，不动产物权以登记为准。案外人未办理过户登记且未实际占有的，不享有足以排除执行的权利。判决驳回异议。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某申请执行人诉被执行人纳入失信名单纠纷案', '某区基层人民法院', '{"cause": "执行案件", "court_level": "基层人民法院", "year": "2022", "summary": "申请执行人请求将被执行人纳入失信名单。法院支持请求。"}', '被执行人吴某拒不履行生效判决确定的还款义务，且有履行能力。申请执行人请求将其纳入失信被执行人名单。法院经审理查明，吴某名下有房产和车辆，具备履行能力但拒不履行。法院认为，被执行人有履行能力而拒不履行的，应当纳入失信被执行人名单。判决将吴某纳入失信被执行人名单并限制高消费。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '案外人李某诉某债权人执行异议之诉案', '某市中级人民法院', '{"cause": "执行案件", "court_level": "中级人民法院", "year": "2023", "summary": "案外人主张被执行车辆系其所有。法院支持异议。"}', '债权人申请执行债务人名下车辆。案外人李某主张该车辆系其出资购买登记在债务人名下。法院经审理查明，购车款由李某支付，保险和日常使用均由李某负责，双方有代持协议。法院认为，案外人有充分证据证明其为实际权利人的，其异议成立。但车辆未办理变更登记存在一定过错。判决不得执行该车辆。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某申请执行人诉被执行人到期债权执行纠纷案', '某市中级人民法院', '{"cause": "执行案件", "court_level": "中级人民法院", "year": "2024", "summary": "申请执行人请求执行被执行人对第三人的到期债权。法院支持执行。"}', '被执行人某公司对第三人享有到期债权200万元但怠于行使。申请执行人请求执行该到期债权。法院经审理查明，第三人对债务无异议且已到期。法院认为，被执行人不能清偿债务但对第三人享有到期债权的，人民法院可以执行该到期债权。判决第三人向申请执行人支付200万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某债权人诉被执行人执行不能纠纷案', '某区基层人民法院', '{"cause": "执行案件", "court_level": "基层人民法院", "year": "2019", "summary": "被执行人确无财产可供执行。法院终结本次执行程序。"}', '申请执行人申请执行被执行人赵某50万元债务。法院经网络查控和线下调查，查明赵某名下无房产、车辆、存款等可供执行财产。法院认为，经调查被执行人确无财产可供执行的，可以裁定终结本次执行程序。申请执行人发现被执行人有可供执行财产的可以申请恢复执行。裁定终结本次执行程序。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某航运公司诉某渔业公司船舶碰撞损害赔偿纠纷案', '某海事法院', '{"cause": "海事海商", "court_level": "中级人民法院", "year": "2018", "summary": "被告渔船违规作业与原告货船碰撞。法院判决被告承担主要责任。"}', '原告某航运公司货船在某海域航行时，与被告某渔业公司渔船发生碰撞，致货船船体受损，货物部分湿损。海事部门认定渔船未遵守航行规则负主要责任。法院经审理查明，碰撞系渔船违规横穿航道所致。法院认为，船舶碰撞过失方应承担损害赔偿责任。判决被告赔偿原告船舶修理费和货物损失共计200万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某进出口公司诉某海运公司海上货物运输合同纠纷案', '某海事法院', '{"cause": "海事海商", "court_level": "中级人民法院", "year": "2019", "summary": "承运人运输途中货物受损。法院判决承运人赔偿。"}', '原告某进出口公司委托被告某海运公司运输一批电子设备至国外港口。货物运抵后收货人发现集装箱进水致设备受损，损失80万元。法院经审理查明，集装箱密封条老化致海水渗入，承运人未尽到妥善管货义务。法院认为，承运人应当妥善谨慎地装载搬移积载运输保管照料和卸载所运货物。判决海运公司赔偿80万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某保险公司诉某救助公司海难救助纠纷案', '某海事法院', '{"cause": "海事海商", "court_level": "中级人民法院", "year": "2020", "summary": "救助方对遇难船舶进行救助后请求救助款。法院支持救助请求。"}', '某货船在海上遭遇风暴遇险，被告某救助公司接到求助后前往救助，成功救助船舶和货物。救助完成后救助公司请求救助报酬300万元。保险公司作为货物保险人主张救助费用过高。法院经审理查明，救助方在恶劣天气下成功救助船舶和货物，救助效果良好。法院认为，海难救助有效果的有权获得救助报酬。判决救助报酬250万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某造船公司诉某航运集团船舶建造合同纠纷案', '某省高级人民法院', '{"cause": "海事海商", "court_level": "高级人民法院", "year": "2021", "summary": "原告为被告建造船舶，被告以质量问题拒付尾款。法院判决支付尾款。"}', '原告某造船公司与被告某航运集团签订船舶建造合同，约定建造一艘散货船，总价8000万元。船舶交付后被告以主机功率不达标为由拒付尾款1500万元。法院经审理查明，主机功率经测试达到合同约定标准，被告已将船舶投入运营。法院认为，造船方按约定成建造并交付船舶的，订造方应当支付价款。判决被告支付尾款1500万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某海运公司诉某港口公司港口作业纠纷案', '某海事法院', '{"cause": "海事海商", "court_level": "中级人民法院", "year": "2022", "summary": "港口装卸作业致货物损坏。法院判决港口公司赔偿。"}', '原告某海运公司船舶在被告某港口公司码头卸货时，因港口吊车操作不当致部分设备坠落损坏，损失50万元。法院经审理查明，港口作业人员操作违规致货物损坏。法院认为，港口经营人应当妥善进行装卸作业。因操作不当致货物损坏的应当承担赔偿责任。判决港口公司赔偿50万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某渔业公司诉某航运公司船舶油污损害赔偿纠纷案', '某海事法院', '{"cause": "海事海商", "court_level": "中级人民法院", "year": "2020", "summary": "被告船舶漏油污染原告养殖区。法院判决被告赔偿。"}', '被告某航运公司船舶在某海域发生漏油事故，油污扩散至原告某渔业公司海水养殖区，致养殖的海产品大量死亡，损失200万元。法院经审理查明，漏油系船舶燃油管路老化破裂所致，航运公司未尽维护义务。法院认为，船舶漏油造成养殖区污染的，船舶所有人应当承担赔偿责任。判决航运公司赔偿200万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某贸易公司诉某海运公司航次租船合同纠纷案', '某海事法院', '{"cause": "海事海商", "court_level": "中级人民法院", "year": "2023", "summary": "出租人未按约定提供船舶。法院判决赔偿。"}', '原告某贸易公司与被告某海运公司签订航次租船合同，约定海运公司提供船舶运输煤炭5万吨。海运公司未在约定时间提供船舶，致贸易公司无法按期交货被下游索赔。法院经审理查明，海运公司迟延提供船舶5天，无正当理由。法院认为，出租人应当按约定提供适航船舶。判决海运公司赔偿贸易公司损失80万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某船东诉某保险公司船舶保险合同纠纷案', '某省高级人民法院', '{"cause": "海事海商", "court_level": "高级人民法院", "year": "2024", "summary": "船舶沉没保险公司拒赔。法院判决保险公司理赔。"}', '原告某船东将其船舶向被告某保险公司投保船舶险。船舶在航行中因触碰水下不明物体进水沉没。保险公司以船舶不适航为由拒赔。法院经审理查明，船舶在出航前已通过年检且证书齐全，不属于不适航。法院认为，保险标的因承保风险造成损失的，保险人应当承担赔偿责任。判决保险公司赔偿船东500万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某海运公司诉某货主海运费纠纷案', '某海事法院', '{"cause": "海事海商", "court_level": "中级人民法院", "year": "2019", "summary": "货主拒付海运费。法院判决支付运费及滞期费。"}', '原告某海运公司为被告某货主运输货物至目的港。货物运抵后货主以部分货物包装破损为由拒付海运费及滞期费。法院经审理查明，包装破损系货主自行包装不当所致，承运人已尽妥善管货义务。船舶在港口等待卸货超时产生滞期费。法院认为，托运人应当按约定支付运费。因托运人原因致船舶滞期的应当支付滞期费。判决货主支付运费及滞期费共计60万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某渔业公司诉某海运公司船舶碰撞纠纷案', '某海事法院', '{"cause": "海事海商", "court_level": "中级人民法院", "year": "2025", "summary": "货船与渔船碰撞致渔船沉没。法院判决货船方承担主要责任。"}', '被告某海运公司货船在航行中与原告某渔业公司渔船碰撞，致渔船沉没、一名船员失踪。海事部门认定货船超速航行且未保持正规瞭望负主要责任。法院经审理查明，货船在渔区航行未减速，瞭望疏忽。法院认为，船舶碰撞过失方应承担损害赔偿责任。判决海运公司赔偿渔船损失、船员伤亡赔偿金等共计300万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某中国公司诉某外国公司涉外买卖合同纠纷案', '某市中级人民法院', '{"cause": "涉外商事", "court_level": "中级人民法院", "year": "2019", "summary": "外国公司违约拒付货款。法院适用中国法律判决。"}', '原告中国某公司与被告某外国公司签订国际货物买卖合同，约定原告向被告出口机械设备，总价100万美元。原告交付货物后被告以质量不合格为由拒付尾款40万美元。法院经审理查明，合同约定适用中国法律，被告未在约定检验期内提出质量异议。法院认为，根据中国法律，买受人未在约定期间内提出质量异议的视为质量合格。判决被告支付尾款40万美元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某中国公司诉某外国公司涉外仲裁裁决承认与执行纠纷案', '某省高级人民法院', '{"cause": "涉外商事", "court_level": "高级人民法院", "year": "2020", "summary": "申请人申请承认和执行外国仲裁裁决。法院裁定予以承认和执行。"}', '申请人某中国公司与被申请人某外国公司在合同中约定在某国仲裁。仲裁庭裁决外国公司向中国公司赔偿200万美元。中国公司向法院申请承认和执行该仲裁裁决。法院经审理查明，该仲裁裁决在作出国已生效，且不存在不予承认和执行的情形。法院认为，根据《纽约公约》，缔约国仲裁裁决应当予以承认和执行。裁定承认并执行该仲裁裁决。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某外国公司诉某中国公司涉外技术转让合同纠纷案', '某市中级人民法院', '{"cause": "涉外商事", "court_level": "中级人民法院", "year": "2021", "summary": "中国公司未按约定支付技术使用费。法院判决支付。"}', '原告某外国公司与被告某中国公司签订技术转让合同，约定外国公司向中国公司转让某项技术，中国公司按销售额5%支付使用费。中国公司支付两年后停止支付。法院经审理查明，中国公司仍在使用该技术生产销售产品但拒付使用费。法院认为，技术受让人应当按照约定支付使用费。判决中国公司支付拖欠使用费300万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某中国公民诉某外国公司涉外侵权纠纷案', '某市中级人民法院', '{"cause": "涉外商事", "court_level": "中级人民法院", "year": "2022", "summary": "外国公司在华产品致人损害。法院判决赔偿。"}', '原告某中国公民购买被告某外国公司在中国销售的电器，使用时因产品缺陷爆炸致原告受伤。法院经审理查明，产品存在设计缺陷，且该缺陷与损害有因果关系。法院认为，因产品存在缺陷造成他人损害的生产者应当承担侵权责任。在中国境内销售的产品造成损害的适用中国法律。判决外国公司赔偿原告医疗费等损失30万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某中外合资企业经营纠纷案', '某省高级人民法院', '{"cause": "涉外商事", "court_level": "高级人民法院", "year": "2023", "summary": "合资双方对利润分配产生争议。法院判决按合同约定分配。"}', '某中外合资企业经营多年后盈利，外方主张按出资比例分配利润，中方主张按合同约定的其他比例分配。法院经审理查明，合资合同明确约定利润按中方55%外方45%分配，与出资比例不同。法院认为，合资企业利润分配应当按照合资合同的约定。判决按合同约定的比例分配利润。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某中国公司诉某外国公司跨境投资纠纷案', '某市中级人民法院', '{"cause": "涉外商事", "court_level": "中级人民法院", "year": "2024", "summary": "外国投资方未按约定注入资金。法院判决承担违约责任。"}', '原告某中国公司与被告某外国公司签订合资协议，约定设立合资公司，外方出资500万美元。外方仅注入200万美元后停止出资。法院经审理查明，外方无正当理由未按约定完成出资。法院认为，合资一方未按约定缴纳出资的应当承担违约责任。判决外方补足出资并赔偿中方损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某中国公司诉某外国公司涉外物权纠纷案', '某省高级人民法院', '{"cause": "涉外商事", "court_level": "高级人民法院", "year": "2022", "summary": "外国公司擅自处分合资财产。法院判决行为无效。"}', '原告某中国公司与被告某外国公司合资期间，外方擅自将合资公司的生产设备运至其关联公司。法院经审理查明，设备属合资公司财产，外方未经董事会同意擅自处分。法院认为，合资企业财产受法律保护，任何一方不得擅自处分。判决外方返还设备并赔偿损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某中国公司诉某外国公司涉外代理合同纠纷案', '某市中级人民法院', '{"cause": "涉外商事", "court_level": "中级人民法院", "year": "2020", "summary": "外国代理商未按约定付款。法院判决支付货款。"}', '原告某中国公司委托被告某外国公司为其在某国的独家代理商。代理商代收货款后未按约定汇回中国公司，累计拖欠80万美元。法院经审理查明，代理商已收取货款但未按约定汇付。法院认为，代理人应当按约定将代收款项交付委托人。判决外国公司支付拖欠货款80万美元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某外国投资者诉某中国企业跨境并购纠纷案', '某省高级人民法院', '{"cause": "涉外商事", "court_level": "高级人民法院", "year": "2025", "summary": "中方企业未按并购协议披露债务。法院判决赔偿。"}', '原告某外国投资者收购被告某中国企业股权。交易完成后发现目标企业有未披露债务500万元。法院经审理查明，转让方在签约时明知存在未披露债务但未告知。法院认为，跨境并购中转让方隐瞒目标企业债务构成违约。判决转让方赔偿投资者500万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某中国公司诉某外国公司涉外货物运输保险纠纷案', '某市中级人民法院', '{"cause": "涉外商事", "court_level": "中级人民法院", "year": "2018", "summary": "国际运输货物损毁保险公司拒赔。法院判决理赔。"}', '原告某中国公司向被告某外国保险公司投保国际运输货物保险。货物在运输中因集装箱落水全损。保险公司以包装不当为由拒赔。法院经审理查明，货物包装符合国际运输标准，落水系承运人操作不当所致。法院认为，保险标的因承保风险造成损失的保险人应当理赔。判决保险公司赔偿100万美元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某环保组织诉某化工企业环境公益诉讼案', '某市中级人民法院', '{"cause": "环境资源", "court_level": "中级人民法院", "year": "2020", "summary": "环保组织起诉企业排放废水污染河流。法院判决企业承担修复责任。"}', '原告某环保组织发现被告某化工企业通过暗管排放未经处理的工业废水至附近河流，致水质严重恶化。原告提起环境公益诉讼。法院经审理查明，被告通过暗管偷排废水，废水中污染物严重超标，对河流生态造成严重损害。法院认为，污染者应当承担生态环境修复责任。判决被告承担生态修复费用500万元并公开赔礼道歉。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某村委会诉某矿业公司生态破坏纠纷案', '某市中级人民法院', '{"cause": "环境资源", "court_level": "中级人民法院", "year": "2019", "summary": "矿业公司采矿致山体破坏。法院判决承担生态修复责任。"}', '被告某矿业公司在采矿过程中未按规定进行生态保护，致原告所在村的山体植被严重破坏，水土流失加剧。法院经审理查明，矿业公司未按环评要求实施生态修复措施。法院认为，开发利用自然资源应当保护生态环境，造成破坏的应当承担修复责任。判决矿业公司承担生态修复费用300万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某检察院诉某电镀厂环境公益诉讼案', '某省高级人民法院', '{"cause": "环境资源", "court_level": "高级人民法院", "year": "2021", "summary": "电镀厂排放重金属废水。检察院提起公益诉讼。法院判决承担惩罚性赔偿。"}', '被告某电镀厂将含重金属的废水直接排入下水道，严重污染土壤和地下水。检察机关提起环境公益诉讼。法院经审理查明，电镀厂长期违法排放含铬含镍废水，周边土壤重金属超标严重。法院认为，污染者除承担修复责任外还应承担惩罚性赔偿。判决电镀厂承担土壤修复费用800万元及惩罚性赔偿200万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某渔民诉某造纸厂渔业污染损害赔偿纠纷案', '某区基层人民法院', '{"cause": "环境资源", "court_level": "基层人民法院", "year": "2018", "summary": "造纸厂排污致渔民养殖鱼类死亡。法院判决赔偿。"}', '被告某造纸厂排放的废水流入原告某渔民的鱼塘，致塘中鱼大量死亡，损失15万元。法院经审理查明，造纸厂排放的废水中污染物超标，与鱼类死亡有因果关系。法院认为，因污染环境造成损害的侵权人应当承担侵权责任。判决造纸厂赔偿渔民损失15万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某林业部门诉某村民滥伐林木纠纷案', '某区基层人民法院', '{"cause": "环境资源", "court_level": "基层人民法院", "year": "2022", "summary": "被告滥伐林木被追究民事责任。法院判决补种林木并赔偿。"}', '被告某村民在未取得采伐许可证的情况下砍伐集体林木200棵。林业部门诉至法院要求承担生态修复责任。法院经审理查明，被告未经许可砍伐林木200棵，破坏森林生态。法院认为，破坏森林资源应当承担生态修复责任。判决被告补种林木600棵并承担管护费用。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某环保组织诉某养殖场水污染公益诉讼案', '某市中级人民法院', '{"cause": "环境资源", "court_level": "中级人民法院", "year": "2023", "summary": "养殖场排放粪污污染水源。法院判决承担治理责任。"}', '被告某养殖场将未经处理的畜禽粪污直接排入附近水库，致水质富营养化。原告某环保组织提起公益诉讼。法院经审理查明，养殖场未建设粪污处理设施，长期直排。法院认为，养殖者应当建设污染防治设施，不得违法排放污染物。判决养殖场建设粪污处理设施并承担水源治理费用200万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某村民诉某砂石厂非法采矿纠纷案', '某区基层人民法院', '{"cause": "环境资源", "court_level": "基层人民法院", "year": "2024", "summary": "砂石厂非法采砂致河道破坏。法院判决承担修复责任。"}', '被告某砂石厂在未取得采矿许可证的情况下在河道非法采砂，致河床下切、河岸崩塌，威胁附近村庄安全。法院经审理查明，砂石厂非法采砂量达5万立方米，严重破坏河道生态。法院认为，非法采矿破坏矿产资源和生态环境的应当承担修复责任。判决砂石厂承担河道修复费用150万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某环保组织诉某电厂大气污染公益诉讼案', '某省高级人民法院', '{"cause": "环境资源", "court_level": "高级人民法院", "year": "2021", "summary": "电厂超标排放废气。法院判决承担治理责任。"}', '被告某电厂脱硫设施运行不正常，长期超标排放二氧化硫和氮氧化物，严重影响周边空气质量。法院经审理查明，电厂脱硫设施故障后未及时维修，超标排放持续时间长。法院认为，排放大气污染物超过排放标准的应当承担治理责任。判决电厂修复脱硫设施并承担大气治理费用300万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某景区诉某企业破坏自然资源纠纷案', '某市中级人民法院', '{"cause": "环境资源", "court_level": "中级人民法院", "year": "2025", "summary": "企业在景区附近施工破坏自然景观。法院判决赔偿。"}', '被告某企业在某风景名胜区附近违规施工，大量开挖山体，破坏景区自然景观。法院经审理查明，企业未办理环评手续即施工，破坏景区景观资源。法院认为，破坏风景名胜区自然景观的应当承担赔偿责任。判决企业承担景观修复费用500万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某村委会诉某化工企业土壤污染纠纷案', '某区基层人民法院', '{"cause": "环境资源", "court_level": "基层人民法院", "year": "2022", "summary": "化工企业搬迁后遗留土壤污染。法院判决承担修复责任。"}', '被告某化工企业搬迁后，原告某村委会发现厂区土壤被重金属严重污染，无法用于农业种植。法院经审理查明，化工企业在经营期间未采取防渗措施，致土壤污染。法院认为，污染者应当承担土壤修复责任。判决化工企业承担土壤修复费用400万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某消费者诉某电商平台网络购物纠纷案', '某区基层人民法院', '{"cause": "互联网纠纷", "court_level": "基层人民法院", "year": "2020", "summary": "消费者在电商平台购买到假货。法院判决平台和商家连带赔偿。"}', '原告某消费者在被告某电商平台购买名牌手表一块，收到商品后发现系假冒产品。消费者要求平台和商家赔偿。法院经审理查明，平台未对商家资质进行严格审核，商家销售假冒商品。法院认为，电子商务平台经营者知道或应当知道平台内经营者销售侵害消费者合法权益的商品未采取必要措施的，依法与该平台内经营者承担连带责任。判决平台和商家连带赔偿消费者三倍购物款。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某用户诉某社交平台数据权益纠纷案', '某市中级人民法院', '{"cause": "互联网纠纷", "court_level": "中级人民法院", "year": "2022", "summary": "平台未经同意使用用户数据推送广告。法院判决侵犯数据权益。"}', '原告某用户发现被告某社交平台未经其同意，使用其聊天数据和行为数据向其推送精准广告。用户诉至法院要求停止使用其数据。法院经审理查明，平台在隐私政策中未明确告知将使用用户聊天数据进行广告推送。法院认为，网络用户对其个人数据享有权益，平台使用用户数据应当取得用户同意。判决平台停止未经同意使用用户数据推送广告。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某玩家诉某游戏公司虚拟财产纠纷案', '某区基层人民法院', '{"cause": "互联网纠纷", "court_level": "基层人民法院", "year": "2021", "summary": "游戏公司封禁玩家账号。法院判决解封并赔偿。"}', '原告某玩家在被告某游戏公司的游戏中投入大量时间和金钱，账号内有价值数万元的虚拟装备。游戏公司以玩家使用外挂为由永久封禁账号。法院经审理查明，玩家未使用外挂，封禁系系统误判。法院认为，网络虚拟财产受法律保护，运营商无正当理由不得封禁用户账号。判决游戏公司解封账号并赔偿玩家损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某公司诉某域名抢注者域名纠纷案', '某市中级人民法院', '{"cause": "互联网纠纷", "court_level": "中级人民法院", "year": "2019", "summary": "被告恶意抢注原告商标为域名。法院判决转移域名。"}', '原告某公司是某知名商标权人。被告在原告商标注册后恶意抢注了包含原告商标的域名，并以此向原告索要高价。法院经审理查明，被告注册域名后未实际使用，系为出售牟利。法院认为，恶意抢注他人商标为域名的应当将域名转移给商标权人。判决被告将域名转移给原告。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某消费者诉某网店网络购物合同纠纷案', '某区基层人民法院', '{"cause": "互联网纠纷", "court_level": "基层人民法院", "year": "2023", "summary": "网店虚假宣传。法院判决三倍赔偿。"}', '原告某消费者在被告某网店购买一款宣称具有治疗功效的保健品，收到后发现仅为普通食品，无任何治疗功效。法院经审理查明，网店在页面宣传中虚构产品功效，构成欺诈。法院认为，经营者提供商品有欺诈行为的应当按照消费者要求增加赔偿其受到的损失，增加赔偿的金额为价款三倍。判决网店退还货款并三倍赔偿。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某博主诉某平台网络侵权纠纷案', '某市中级人民法院', '{"cause": "互联网纠纷", "court_level": "中级人民法院", "year": "2024", "summary": "平台未经授权使用博主原创内容。法院判决赔偿。"}', '原告某博主在某平台发布原创视频。被告另一平台未经博主同意将视频搬运至自家平台播放获取流量。法院经审理查明，被告平台未经授权复制传播原告作品。法院认为，未经著作权人许可通过信息网络传播其作品构成侵权。判决被告停止侵权并赔偿原告10万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某用户诉某App侵犯个人信息纠纷案', '某区基层人民法院', '{"cause": "互联网纠纷", "court_level": "基层人民法院", "year": "2025", "summary": "App过度收集用户个人信息。法院判决删除并赔偿。"}', '原告某用户发现被告某App在未经同意的情况下收集其通讯录、位置等与提供服务无关的个人信息。法院经审理查明，App收集的个人信息超出其服务功能所需范围。法院认为，处理个人信息应当遵循合法正当必要原则，不得过度收集。判决App删除不当收集的个人信息并赔偿用户损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某商家诉某电商平台不正当竞争纠纷案', '某市中级人民法院', '{"cause": "互联网纠纷", "court_level": "中级人民法院", "year": "2023", "summary": "电商平台强制商家二选一。法院判决构成不正当竞争。"}', '原告某商家在被告某电商平台和另一平台同时开店经营。被告平台以流量降权为由要求原告关闭另一平台店铺。法院经审理查明，被告利用市场支配地位强制商家独家经营。法院认为，经营者不得利用技术手段优势地位等强迫交易相对人接受不合理条件。判决被告停止二选一行为并赔偿商家损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某用户诉某直播平台虚拟财产纠纷案', '某区基层人民法院', '{"cause": "互联网纠纷", "court_level": "基层人民法院", "year": "2022", "summary": "用户充值后平台关闭。法院判决退还余额。"}', '原告某用户在被告某直播平台充值5万元购买虚拟币用于打赏主播。后平台因经营不善关闭，用户账户中尚有余额3万元未使用。法院经审理查明，平台关闭后未退还用户预付费用。法院认为，网络服务提供者终止服务的应当退还用户预付但未消费的费用。判决平台退还用户3万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某消费者诉某外卖平台侵权纠纷案', '某区基层人民法院', '{"cause": "互联网纠纷", "court_level": "基层人民法院", "year": "2024", "summary": "外卖骑手配送时撞伤消费者。法院判决平台承担赔偿责任。"}', '原告某消费者在某小区被被告某外卖平台的骑手撞伤。骑手配送途中超速行驶，致消费者骨折。法院经审理查明，骑手系平台注册骑手，平台对骑手有管理和控制权。法院认为，网络平台对注册骑手有管理控制权的，骑手在配送过程中致人损害的由平台承担赔偿责任。判决平台赔偿消费者医疗费等损失5万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某企业诉某网络公司流量劫持纠纷案', '某市中级人民法院', '{"cause": "互联网纠纷", "court_level": "中级人民法院", "year": "2021", "summary": "被告通过技术手段劫持原告网站流量。法院判决构成不正当竞争。"}', '原告某企业运营某电商网站。被告某网络公司通过技术手段使用户访问原告网站时跳转至被告网站。法院经审理查明，被告利用恶意代码实施流量劫持。法院认为，经营者不得利用技术手段通过影响用户选择干扰其他经营者正常经营。判决被告停止流量劫持行为并赔偿原告50万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某用户诉某网约车平台侵权纠纷案', '某区基层人民法院', '{"cause": "互联网纠纷", "court_level": "基层人民法院", "year": "2020", "summary": "网约车司机殴打乘客。法院判决平台承担补充责任。"}', '原告某用户乘坐被告某网约车平台车辆时因路线问题与司机发生争执，被司机殴打受伤。法院经审理查明，司机有暴力犯罪前科，平台未尽到安全审核义务。法院认为，网约车平台应当对驾驶员进行背景审查确保乘客安全。平台未尽到安全保障义务的承担补充责任。判决司机赔偿用户损失，平台承担补充责任。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某投资者诉某上市公司证券虚假陈述纠纷案', '某省高级人民法院', '{"cause": "金融证券", "court_level": "高级人民法院", "year": "2020", "summary": "上市公司虚假陈述致投资者损失。法院判决赔偿。"}', '被告某上市公司在年报中虚增利润5000万元。证监会对其作出行政处罚后，原告投资者以虚假陈述致其投资损失为由提起诉讼。法院经审理查明，公司虚增利润的虚假陈述行为与投资者买入股票的损失存在因果关系。法院认为，证券虚假陈述实施后投资人买入并产生损失的，虚假陈述行为人应当承担赔偿责任。判决上市公司赔偿投资者损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某投资者诉某公司内幕交易纠纷案', '某市中级人民法院', '{"cause": "金融证券", "court_level": "中级人民法院", "year": "2021", "summary": "公司高管内幕交易致投资者损失。法院判决赔偿。"}', '被告某公司高管在公司重大资产重组信息公告前利用内幕信息买入公司股票获利。原告投资者以内幕交易致其损失为由提起诉讼。法院经审理查明，被告利用内幕信息交易获利，内幕交易行为与投资者损失存在因果关系。法院认为，内幕交易行为人应当对在内幕交易期间反向交易的投资者承担赔偿责任。判决被告赔偿投资者损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某投保人诉某保险公司保险合同纠纷案', '某区基层人民法院', '{"cause": "金融证券", "court_level": "基层人民法院", "year": "2019", "summary": "保险公司以未如实告知为由拒赔。法院判决理赔。"}', '原告投保人投保重疾险后确诊癌症，被告保险公司以投保时未告知既往症为由拒赔。法院经审理查明，投保人投保前的体检报告未显示相关疾病，不存在未如实告知情形。法院认为，投保人已履行如实告知义务，保险公司应当按合同约定理赔。判决保险公司支付保险金50万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某投资者诉某信托公司信托纠纷案', '某市中级人民法院', '{"cause": "金融证券", "court_level": "中级人民法院", "year": "2022", "summary": "信托产品亏损投资者要求赔偿。法院判决信托公司承担赔偿责任。"}', '原告某投资者购买被告某信托公司发行的信托产品，信托公司将资金投向高风险项目致全部亏损。法院经审理查明，信托公司未按合同约定进行风险控制，未履行审慎管理义务。法院认为，受托人违反信托目的处分信托财产或未履行审慎管理义务致使信托财产损失的应当承担赔偿责任。判决信托公司赔偿投资者损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某公司诉某银行金融借款合同纠纷案', '某区基层人民法院', '{"cause": "金融证券", "court_level": "基层人民法院", "year": "2018", "summary": "银行以企业违约为由提前收回贷款。法院判决银行违约。"}', '原告某公司向被告某银行贷款500万元，按期付息。银行以企业经营状况恶化为由提前收回贷款。法院经审理查明，企业经营正常，不存在合同约定的提前收回贷款情形。法院认为，银行未按合同约定提前收回贷款构成违约。判决银行继续履行借款合同并赔偿企业损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某投资者诉某证券公司融资融券纠纷案', '某市中级人民法院', '{"cause": "金融证券", "court_level": "中级人民法院", "year": "2023", "summary": "证券公司强平致投资者损失。法院判决部分赔偿。"}', '原告某投资者在被告某证券公司开通融资融券账户。市场波动时证券公司强制平仓致投资者损失扩大。法院经审理查明，证券公司未按合同约定的平仓线进行平仓，且未及时通知投资者。法院认为，证券公司未按合同约定执行强平且未尽通知义务的应当承担相应责任。判决证券公司赔偿投资者部分损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某银行诉某公司信用证纠纷案', '某市中级人民法院', '{"cause": "金融证券", "court_level": "中级人民法院", "year": "2024", "summary": "公司提交虚假单据骗取信用证款项。法院判决银行不承担付款责任。"}', '被告某公司向原告某银行申请开立信用证用于进口货物。银行开立信用证后发现被告提交的提单等单据系伪造。法院经审理查明，被告提交虚假单据存在欺诈行为。法院认为，信用证交易中存在欺诈的银行可以拒绝付款。判决银行不承担信用证项下付款责任。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某投资者诉某基金公司基金纠纷案', '某区基层人民法院', '{"cause": "金融证券", "court_level": "基层人民法院", "year": "2020", "summary": "基金公司未按约定投资致亏损。法院判决赔偿。"}', '原告某投资者购买被告某基金公司发行的保本型基金。基金公司未按合同约定投资于低风险资产，将大部分资金投入股市致亏损。法院经审理查明，基金公司违反基金合同约定的投资范围和比例。法院认为，基金管理人未履行勤勉尽责义务违反基金合同约定的应当承担赔偿责任。判决基金公司赔偿投资者损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某银行诉某企业票据纠纷案', '某市中级人民法院', '{"cause": "金融证券", "court_level": "中级人民法院", "year": "2022", "summary": "企业签发空头支票。法院判决承担票据责任。"}', '被告某企业向原告某银行签发支票一张金额50万元。银行提示付款时企业账户余额不足遭退票。法院经审理查明，企业签发支票时账户余额不足，构成空头支票。法院认为，签发空头支票的应当承担票据责任。判决企业支付银行50万元及利息。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某投资者诉某上市公司操纵市场纠纷案', '某省高级人民法院', '{"cause": "金融证券", "court_level": "高级人民法院", "year": "2023", "summary": "上市公司操纵股价致投资者损失。法院判决赔偿。"}', '被告某上市公司通过连续买卖自买自卖等方式操纵公司股价。证监会对其作出处罚后投资者提起诉讼。法院经审理查明，公司操纵证券市场行为与投资者损失存在因果关系。法院认为，操纵证券市场行为给投资者造成损失的应当承担赔偿责任。判决公司赔偿投资者损失。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某企业诉某保险公司财产保险纠纷案', '某区基层人民法院', '{"cause": "金融证券", "court_level": "基层人民法院", "year": "2019", "summary": "企业财产被盗保险公司拒赔。法院判决理赔。"}', '原告某企业向被告某保险公司投保财产综合险。投保后企业仓库被盗损失80万元。保险公司以企业未安装报警系统为由拒赔。法院经审理查明，保险合同中未约定必须安装报警系统。法院认为，保险标的发生保险事故的保险人应当按约理赔。保险公司不能以合同未约定的条件拒赔。判决保险公司赔偿80万元。', 0, NOW()),

('PUBLIC', NULL, 'CASE', '某投资者诉某证券公司代销金融产品纠纷案', '某市中级人民法院', '{"cause": "金融证券", "court_level": "中级人民法院", "year": "2025", "summary": "证券公司代销不合格产品致投资者损失。法院判决承担赔偿责任。"}', '原告某投资者通过被告某证券公司代销购买了一款私募基金产品，后该基金被认定为非法集资产品被清退。法院经审理查明，证券公司未对代销产品进行充分尽职调查。法院认为，金融产品代销机构应当对代销产品进行尽职调查确保产品合规。代销机构未尽审慎义务的承担赔偿责任。判决证券公司赔偿投资者损失。', 0, NOW());
